export const words: PolishWord[] = [
  // ===== FILOZOFIA =====
  { id: "1", word: "Aprioryczny", partOfSpeech: "przymiotnik", definition: "Oparty na rozumowaniu, a nie na doświadczeniu; z góry założony. W filozofii Kanta odnosi się do wiedzy niezależnej od doświadczenia zmysłowego. Pojęcie kluczowe dla epistemologii i teorii poznania.", example: "1. Jego aprioryczne przekonania nie miały oparcia w faktach.\n2. Kant twierdził, że matematyka opiera się na apriorycznych sądach syntetycznych.", etymology: "z łac. a priori — z tego, co wcześniejsze", category: "filozofia", difficulty: "advanced" },
  { id: "4", word: "Demiurg", partOfSpeech: "rzeczownik", definition: "Twórca, stwórca; w filozofii platońskiej — boski budowniczy świata, który nadaje formę bezkształtnej materii. Demiurg nie tworzy z niczego, lecz porządkuje istniejący chaos. Pojęcie to odegrało ważną rolę w gnostycyzmie.", example: "1. Pisarz stał się demiurgiem własnego literackiego uniwersum.\n2. W filozofii Platona demiurg kształtuje świat na wzór wiecznych idei.", category: "filozofia", difficulty: "advanced" },
  { id: "6", word: "Egzegeza", partOfSpeech: "rzeczownik", definition: "Naukowy komentarz i interpretacja tekstu, zwłaszcza biblijnego lub prawniczego. Egzegeza dąży do odkrycia oryginalnego znaczenia tekstu w jego historycznym kontekście. Jest fundamentem hermeneutyki.", example: "1. Egzegeza tego fragmentu Ewangelii zajęła uczonym lata badań.\n2. Współczesna egzegeza uwzględnia kontekst kulturowy i językowy starożytnych tekstów.", etymology: "z gr. exēgēsis — wyjaśnienie", category: "filozofia", difficulty: "advanced" },
  { id: "12", word: "Immanentny", partOfSpeech: "przymiotnik", definition: "Tkwiący wewnętrznie w czymś, nieodłączny, będący istotną częścią danej rzeczy. W filozofii przeciwstawiany temu, co transcendentne — zewnętrzne i przekraczające. Pojęcie ważne zarówno w teologii, jak i w metafizyce.", example: "1. Ciekawość jest immanentną cechą ludzkiej natury.\n2. Spinoza twierdził, że Bóg jest immanentny — obecny w każdym aspekcie przyrody.", category: "filozofia", difficulty: "advanced" },
  { id: "32", word: "Solipsyzm", partOfSpeech: "rzeczownik", definition: "Pogląd filozoficzny, że istnieje tylko własne ja i jego przeżycia, a cały świat zewnętrzny jest jedynie projekcją umysłu. Jest to skrajna forma subiektywizmu, logicznie trudna do obalenia, choć praktycznie absurdalna. Stanowi ważny eksperyment myślowy w filozofii umysłu.", example: "1. Solipsyzm jest skrajną formą subiektywizmu — nikt nie może go w pełni żyć.\n2. Filozof żartował, że solipsyzm to idealna filozofia, ale trudno z nią założyć klub dyskusyjny.", etymology: "z łac. solus ipse — sam jedyny", category: "filozofia", difficulty: "advanced" },
  { id: "46", word: "Gnozeologia", partOfSpeech: "rzeczownik", definition: "Dział filozofii badający źródła, granice i naturę ludzkiego poznania. Gnozeologia stawia pytanie, czy i jak możemy poznać prawdę o świecie. Jest blisko spokrewniona z epistemologią, choć tradycja kontynentalna je rozróżnia.", example: "1. Gnozeologia Kanta zrewolucjonizowała europejską myśl filozoficzną.\n2. Współczesna gnozeologia bada, czy sztuczna inteligencja może posiadać wiedzę.", category: "filozofia", difficulty: "advanced" },
  { id: "47", word: "Hubris", partOfSpeech: "rzeczownik", definition: "Pycha, zuchwałość; nadmierna pewność siebie prowadząca do upadku. W tragedii greckiej hubris była główną przyczyną katastrofy bohatera — karą bogów za próbę przekroczenia ludzkiej miary. Pojęcie to pozostaje aktualne w analizie władzy i ambicji.", example: "1. Hubris dyrektora, który ignorował ostrzeżenia, doprowadził firmę do bankructwa.\n2. Starożytni Grecy wierzyli, że hubris ściąga gniew bogów — Nemezis.", etymology: "z gr. hybris", category: "filozofia", difficulty: "intermediate" },
  { id: "15", word: "Kontemplacja", partOfSpeech: "rzeczownik", definition: "Głębokie, skupione rozmyślanie; duchowe skupienie na przedmiocie medytacji. Kontemplacja różni się od zwykłego myślenia tym, że angażuje całą osobę, łącząc intelekt z uczuciem. W tradycji zachodniej stanowi najwyższy stopień życia duchowego.", example: "1. Pogrążył się w kontemplacji zachodu słońca nad jeziorem.\n2. Mnisi benedyktyńscy uważali kontemplację za najważniejszy element ich powołania.", category: "filozofia", difficulty: "beginner" },
  { id: "35", word: "Transgresja", partOfSpeech: "rzeczownik", definition: "Przekroczenie granic, norm, konwencji — zarówno społecznych, jak i artystycznych. Transgresja może być aktem odwagi i twórczości lub destrukcji. W filozofii Georges'a Bataille'a jest sposobem dotarcia do doświadczeń granicznych.", example: "1. Sztuka awangardowa często opiera się na transgresji — łamaniu zastanych reguł.\n2. Transgresja norm społecznych bywa pierwszym krokiem do zmiany świata.", category: "filozofia", difficulty: "intermediate" },
  { id: "50", word: "Liminalny", partOfSpeech: "przymiotnik", definition: "Dotyczący progu, graniczny, przejściowy — opisujący stan zawieszenia między dwiema fazami. Pojęcie rozwinął antropolog Victor Turner, badając rytuały przejścia. Stan liminalny cechuje się niepewnością, ale też ogromnym potencjałem transformacji.", example: "1. Adolescencja to okres liminalny między dzieciństwem a dorosłością.\n2. Lotniska są przestrzeniami liminalnymi — ani tu, ani tam.", category: "filozofia", difficulty: "advanced" },
  { id: "f11", word: "Dialektyka", partOfSpeech: "rzeczownik", definition: "Metoda filozoficzna oparta na zderzeniu przeciwstawnych tez (tezy i antytezy) i wypracowaniu syntezy. Dialektyka Hegla stała się fundamentem jego systemu filozoficznego i wywarła ogromny wpływ na Marksa. Jest to sztuka prowadzenia dyskusji ku prawdzie.", example: "1. Dialektyka Sokratesa polegała na zadawaniu pytań, które obnażały sprzeczności rozmówcy.\n2. Hegel widział w dialektyce motor napędzający historię ludzkości.", etymology: "z gr. dialektikē — sztuka dyskusji", category: "filozofia", difficulty: "intermediate" },
  { id: "f12", word: "Nihilizm", partOfSpeech: "rzeczownik", definition: "Pogląd filozoficzny negujący wszelkie wartości, sens i cel istnienia. Nietzsche diagnozował nihilizm jako chorobę współczesnej cywilizacji po 'śmierci Boga'. Nihilizm może być punktem wyjścia do tworzenia nowych wartości.", example: "1. Po stracie bliskiej osoby popadł w nihilizm — nic nie miało sensu.\n2. Nietzsche widział w nihilizmie szansę na przewartościowanie wszystkich wartości.", category: "filozofia", difficulty: "intermediate" },
  { id: "f13", word: "Fenomenologia", partOfSpeech: "rzeczownik", definition: "Kierunek filozoficzny Husserla badający zjawiska takimi, jakimi jawią się świadomości, bez przesądzania o ich obiektywnym istnieniu. Fenomenologia postuluje 'powrót do samych rzeczy' i zawieszenie naturalnego nastawienia. Wywarła ogromny wpływ na egzystencjalizm.", example: "1. Fenomenologia Husserla zmieniła sposób myślenia o świadomości i percepcji.\n2. Heidegger rozwinął fenomenologię w kierunku pytania o sens bycia.", etymology: "z gr. phainomenon — to, co się ukazuje", category: "filozofia", difficulty: "advanced" },
  { id: "f14", word: "Utylitaryzm", partOfSpeech: "rzeczownik", definition: "Doktryna etyczna głosząca, że moralnie słuszne jest działanie przynoszące największe szczęście największej liczbie ludzi. Utylitaryzm Benthama i Milla jest jedną z najważniejszych teorii etycznych nowożytności. Krytycy zarzucają mu pomijanie praw jednostki.", example: "1. Z punktu widzenia utylitaryzmu, decyzja powinna maksymalizować ogólne dobro.\n2. Dylemat wagonika jest klasycznym testem intuicji utylitarystycznych.", category: "filozofia", difficulty: "intermediate" },
  { id: "f15", word: "Sofizmat", partOfSpeech: "rzeczownik", definition: "Rozumowanie pozornie poprawne logicznie, ale w istocie błędne — celowo mylące. Sofiści starożytnej Grecji posługiwali się sofizmatami w retoryce i nauczaniu. Dziś termin oznacza każdy podstępny argument.", example: "1. Jego argumentacja wyglądała przekonująco, ale okazała się sofizmatem.\n2. Klasyczny sofizmat: 'Czego nie zgubiłeś, masz. Nie zgubiłeś rogów. Więc masz rogi.'", etymology: "z gr. sophisma — sztuczka", category: "filozofia", difficulty: "beginner" },

  // ===== LITERATURA =====
  { id: "23", word: "Palimpsest", partOfSpeech: "rzeczownik", definition: "Rękopis, z którego zmyto lub zeskrobano pierwotny tekst i napisano nowy. Dzięki nowoczesnym technologiom naukowcy potrafią odczytać ukryte warstwy tekstu. Przenośnie oznacza coś, co nosi ślady wcześniejszych wersji.", example: "1. Naukowcy odkryli pod tekstem palimpsestu starożytny traktat Archimedesa.\n2. Miasto jest palimpsestem — pod nowoczesnymi budynkami kryją się warstwy historii.", category: "literatura", difficulty: "advanced" },
  { id: "42", word: "Apokryficzny", partOfSpeech: "przymiotnik", definition: "Nieautentyczny, zmyślony, o wątpliwym autorstwie; dotyczący apokryfów — tekstów niebędących częścią kanonu. Apokryfy biblijne przez wieki kształtowały wyobraźnię religijną Europy. Przenośnie — o opowieściach o niepewnej wiarygodności.", example: "1. Ta historia jest apokryficzna — nie ma potwierdzenia w żadnych źródłach historycznych.\n2. Apokryficzna Ewangelia Tomasza zawiera logiony Jezusa nieznane z kanonu.", category: "literatura", difficulty: "intermediate" },
  { id: "10", word: "Hermetyczny", partOfSpeech: "przymiotnik", definition: "Szczelnie zamknięty, niedostępny; trudny do zrozumienia dla postronnych. W literaturze określa teksty wymagające głębokiej wiedzy i analizy. Termin pochodzi od Hermesa Trismegistosa, legendarnego autora tajemnych pism.", example: "1. Jego wiersze są hermetyczne i wymagają wielokrotnej lektury oraz komentarza.\n2. Środowisko naukowe bywa hermetyczne — trudno się do niego dostać bez odpowiednich kontaktów.", category: "literatura", difficulty: "intermediate" },
  { id: "27", word: "Prolegomena", partOfSpeech: "rzeczownik (l.mn.)", definition: "Wstęp, wprowadzenie do jakiejś nauki lub dzieła; rozważania wstępne określające zakres i metody badań. Termin ten nadał tytuł słynnej pracy Kanta 'Prolegomena do wszelkiej przyszłej metafizyki'. Używany głównie w kontekście akademickim i naukowym.", example: "1. Prolegomena do dzieła liczyły ponad sto stron, ale były niezbędne do zrozumienia reszty.\n2. Profesor rozpoczął wykład od prolegomenów — określenia podstawowych pojęć.", category: "literatura", difficulty: "advanced" },
  { id: "49", word: "Kabotyn", partOfSpeech: "rzeczownik", definition: "Osoba zachowująca się teatralnie i afektowanie, szukająca poklasku za wszelką cenę. Kabotyn gra nie tylko na scenie, ale przede wszystkim w życiu codziennym. Słowo to niesie silne zabarwienie pejoratywne.", example: "1. Nie znosiła kabotynów, którzy grają nawet poza sceną i rozmową zamieniają w spektakl.\n2. Polityk okazał się kabotynem — piękne gesty przed kamerami, a za kulisami cynizm.", category: "literatura", difficulty: "intermediate" },
  { id: "44", word: "Eklektyczny", partOfSpeech: "przymiotnik", definition: "Łączący różne style, elementy z różnych źródeł i tradycji w jedną całość. Eklektyzm bywa oznaką szerokości horyzontów, ale także braku oryginalności. W architekturze i sztuce eklektyzm był dominującym stylem XIX wieku.", example: "1. Jej eklektyczny gust muzyczny obejmował jazz, metal i tradycyjne pieśni bałkańskie.\n2. Eklektyczna architektura Łodzi łączy secesję, neogotyk i modernizm na jednej ulicy.", category: "literatura", difficulty: "intermediate" },
  { id: "18", word: "Meandry", partOfSpeech: "rzeczownik (l.mn.)", definition: "Zakręty, zawiłości, skomplikowane koleje czegoś. Przenośnie oznacza skomplikowane, kręte ścieżki procesu, myśli lub biurokracji. Nazwa pochodzi od rzeki Meander w Azji Mniejszej, słynącej z licznych zakrętów.", example: "1. Meandry polskiej biurokracji potrafią zaskoczyć nawet doświadczonego urzędnika.\n2. Przez meandry jego rozumowania trudno było przebrnąć bez notatek.", etymology: "od rzeki Meander w Azji Mniejszej", category: "literatura", difficulty: "beginner" },
  { id: "7", word: "Efemeryczny", partOfSpeech: "przymiotnik", definition: "Krótkotrwały, przemijający, nietrwały — istniejący zaledwie chwilę. Termin pochodzi od greckiego ephemeros, oznaczającego 'jednodniowy'. Używany zarówno w kontekście biologicznym (np. jętki żyjące jeden dzień), jak i przenośnym.", example: "1. Sława w mediach społecznościowych jest efemeryczna — dziś viral, jutro zapomnienie.\n2. Efemeryczna piękność kwitnącej wiśni jest centralnym motywem japońskiej estetyki.", category: "literatura", difficulty: "intermediate" },
  { id: "38", word: "Wernisaż", partOfSpeech: "rzeczownik", definition: "Uroczyste otwarcie wystawy artystycznej, połączone z prezentacją dzieł i spotkaniem z artystą. Nazwa pochodzi od dawnego zwyczaju lakierowania obrazów (vernissage) przed wystawą. Dziś to wydarzenie towarzyskie i kulturalne.", example: "1. Na wernisażu pojawiło się wielu krytyków sztuki i kolekcjonerów.\n2. Artysta był tak zdenerwowany przed wernisażem, że o mało nie uciekł z własnej wystawy.", etymology: "z fr. vernissage — lakierowanie", category: "literatura", difficulty: "beginner" },
  { id: "36", word: "Truizm", partOfSpeech: "rzeczownik", definition: "Banalne, oczywiste stwierdzenie, które nie wnosi nic nowego; komunał. Truizmy bywają irytujące, bo podają się za mądrości, będąc jedynie powtórzeniem oczywistości. W retoryce truizmy są używane, by wzbudzić pozorne porozumienie.", example: "1. Mówienie, że czas to pieniądz, to truizm — każdy to wie, nikt się tym nie kieruje.\n2. Jego przemówienie składało się z samych truizmów i nie powiedział niczego nowego.", category: "literatura", difficulty: "beginner" },
  { id: "l11", word: "Anakolut", partOfSpeech: "rzeczownik", definition: "Błąd składniowy polegający na niezakończeniu rozpoczętej konstrukcji gramatycznej i przejściu do innej. W literaturze bywa celowym zabiegiem stylistycznym oddającym wzburzenie lub potok świadomości. W mowie potocznej zdarza się często i mimowolnie.", example: "1. 'Kiedy myślę o tym, co się stało — ale nieważne, porozmawiajmy o czymś innym' — to anakolut.\n2. Proust świadomie stosował anakoluty, by oddać chaotyczny bieg myśli bohaterów.", etymology: "z gr. anakolouthon — niekonsekwentny", category: "literatura", difficulty: "advanced" },
  { id: "l12", word: "Litota", partOfSpeech: "rzeczownik", definition: "Figura retoryczna polegająca na celowym umniejszeniu, wyrażeniu czegoś przez zaprzeczenie przeciwieństwa. Litota jest subtelną formą ironii i elegancji stylistycznej. Często spotykana w literaturze angielskiej i polskiej.", example: "1. 'To nie najgorsza praca' — litota oznaczająca, że praca jest całkiem dobra.\n2. 'Niegłupi z niego człowiek' to litota — w istocie mówca uważa go za bardzo mądrego.", etymology: "z gr. litotēs — prostota", category: "literatura", difficulty: "intermediate" },
  { id: "l13", word: "Perypetia", partOfSpeech: "rzeczownik", definition: "Nagły zwrot akcji w utworze literackim, zmiana losu bohatera — zwykle ze szczęścia w nieszczęście. Arystoteles uważał perypetię za kluczowy element tragedii. W mowie potocznej — przygoda, komplikacja.", example: "1. Perypetie podróży autostopem dostarczyły mu materiału na całą powieść.\n2. W 'Królu Edypie' perypetia następuje, gdy bohater dowiaduje się prawdy o swoim pochodzeniu.", etymology: "z gr. peripeteia — nagła zmiana", category: "literatura", difficulty: "beginner" },
  { id: "l14", word: "Onomatopeja", partOfSpeech: "rzeczownik", definition: "Wyrazy naśladujące dźwięki naturalne, np. 'bum', 'miau', 'szum'. Onomatopeja jest jednym z najbardziej podstawowych środków stylistycznych, obecnym we wszystkich językach świata. Poeci wykorzystują ją do tworzenia efektów dźwiękowych.", example: "1. 'Kumka żaba, brzęczy mucha, syczy wąż' — zdanie pełne onomatopei.\n2. Leśmian był mistrzem onomatopei — jego wiersze dosłownie brzmią jak lasy i deszcze.", etymology: "z gr. onomatopoeia — tworzenie nazw", category: "literatura", difficulty: "beginner" },
  { id: "l15", word: "Synekdocha", partOfSpeech: "rzeczownik", definition: "Figura retoryczna polegająca na zastąpieniu nazwy całości nazwą części lub odwrotnie. Synekdocha jest blisko spokrewniona z metonimią i często z nią mylona. Jest powszechna w języku codziennym — często nie zdajemy sobie sprawy, że jej używamy.", example: "1. 'Polska zdobyła złoty medal' — synekdocha, bo grał zespół, nie cały kraj.\n2. 'Potrzebuję pary rąk do pomocy' — synekdocha oznaczająca osobę.", etymology: "z gr. synekdochē — współrozumienie", category: "literatura", difficulty: "intermediate" },

  // ===== OGÓLNE =====
  { id: "2", word: "Atawizm", partOfSpeech: "rzeczownik", definition: "Nawrót do cech przodków; przeżytek z dawnych czasów, który ujawnia się po pokoleniach nieobecności. W biologii oznacza pojawienie się cechy typowej dla dalszych przodków. Przenośnie — anachroniczne zachowanie lub zwyczaj.", example: "1. Ta tradycja to swoisty atawizm kulturowy — nikt nie pamięta, skąd się wzięła.\n2. Narośl na kości ogonowej uznano za biologiczny atawizm — pozostałość po ogonie przodków.", etymology: "z łac. atavus — przodek", category: "ogólne", difficulty: "intermediate" },
  { id: "3", word: "Bigoteria", partOfSpeech: "rzeczownik", definition: "Przesadna, ślepa pobożność pozbawiona głębszego zrozumienia wiary; dewocja. Bigot trzyma się litery przepisów religijnych, ignorując ich ducha. Termin niesie silne zabarwienie pejoratywne.", example: "1. Jej bigoteria budziła niepokój bliskich — modliła się godzinami, ale nie rozmawiała z rodziną.\n2. Bigoteria przejawia się w osądzaniu innych przy jednoczesnym ignorowaniu własnych wad.", etymology: "z fr. bigoterie", category: "ogólne", difficulty: "intermediate" },
  { id: "5", word: "Dyletant", partOfSpeech: "rzeczownik", definition: "Osoba zajmująca się czymś powierzchownie, bez głębszej wiedzy i profesjonalnego przygotowania. Dyletant bywa entuzjastyczny, ale jego brak kompetencji prowadzi do błędów. Początkowo termin ten nie miał pejoratywnego zabarwienia — oznaczał po prostu amatora-pasjonata.", example: "1. Nie chcę, żeby jakiś dyletant naprawiał mi samochód — wolę fachowca.\n2. W XVI wieku dyletantem nazywano kogoś, kto uprawiał sztukę z miłości, nie dla zysku.", category: "ogólne", difficulty: "beginner" },
  { id: "8", word: "Endemiczny", partOfSpeech: "przymiotnik", definition: "Występujący wyłącznie na określonym, ograniczonym obszarze geograficznym. Gatunki endemiczne powstają w wyniku długiej izolacji od reszty populacji. Ich utrata jest nieodwracalna — nie istnieją nigdzie indziej na świecie.", example: "1. Ten gatunek żaby jest endemiczny dla wyspy Borneo — nie spotkamy go nigdzie indziej.\n2. Endemiczna flora Madagaskaru obejmuje ponad 80% gatunków roślin nieznanych z innych miejsc.", category: "ogólne", difficulty: "intermediate" },
  { id: "9", word: "Filister", partOfSpeech: "rzeczownik", definition: "Człowiek o ciasnych horyzontach, nieczuły na sztukę, kulturę i wyższe wartości duchowe. Termin popularny wśród romantyków, którzy przeciwstawiali artystę filisterowi. Filister zadowala się konwencją i boi się wszystkiego, co nowe.", example: "1. Nie bądź filistrem — spróbuj chociaż raz pójść do opery i otworzyć się na nowe doznania.\n2. Romantycy pogardzali filistrami — drobnomieszczanami zadowolonymi ze swojej ciasnej wygody.", category: "ogólne", difficulty: "advanced" },
  { id: "11", word: "Idiosynkrazja", partOfSpeech: "rzeczownik", definition: "Wrodzona, irracjonalna niechęć lub odraza do czegoś lub kogoś, wykraczająca poza zwykłą antypatię. W medycynie oznacza nietypową reakcję organizmu na lek lub pokarm. Jest to głęboko osobista i trudna do racjonalnego wytłumaczenia.", example: "1. Miała idiosynkrazję na dźwięk skrzypiec — nawet najpiękniejsza sonata wywoływała u niej gęsią skórkę.\n2. Jego idiosynkrazja wobec szpinaku sięgała dzieciństwa i nie dała się przezwyciężyć.", etymology: "z gr. idiosynkrasia", category: "ogólne", difficulty: "advanced" },
  { id: "13", word: "Jurysdykcja", partOfSpeech: "rzeczownik", definition: "Zakres władzy sądowniczej lub administracyjnej; kompetencja do rozstrzygania spraw na danym obszarze. Jurysdykcja określa, który sąd lub organ jest właściwy dla danej sprawy. W prawie międzynarodowym kwestia jurysdykcji bywa źródłem sporów między państwami.", example: "1. Ta sprawa nie podlega jurysdykcji polskich sądów — musi być rozpatrzona w Hadze.\n2. Spory o jurysdykcję w cyberprzestrzeni stanowią jedno z największych wyzwań współczesnego prawa.", category: "ogólne", difficulty: "intermediate" },
  { id: "14", word: "Koniunktura", partOfSpeech: "rzeczownik", definition: "Sprzyjający układ okoliczności, zwłaszcza gospodarczych; faza wzrostu gospodarczego. Koniunktura podlega cyklom — po okresie prosperity przychodzi kryzys. W mowie potocznej oznacza po prostu pomyślny zbieg okoliczności.", example: "1. Firma rozwijała się dzięki dobrej koniunkturze rynkowej lat 2010–2020.\n2. Dobra koniunktura na rynku nieruchomości sprawiła, że ceny mieszkań poszybowały.", category: "ogólne", difficulty: "beginner" },
  { id: "16", word: "Lakoniczny", partOfSpeech: "przymiotnik", definition: "Zwięzły, treściwy, wyrażony w niewielu, ale trafnych słowach. Nazwa pochodzi od Lakonii — regionu starożytnej Sparty, której mieszkańcy słynęli ze zwięzłości. Lakońska odpowiedź jest mistrzostwem komunikacji — mówi wiele przy użyciu minimum słów.", example: "1. Jego lakoniczna odpowiedź — 'Nie' — nie pozostawiała wątpliwości.\n2. Filip Macedoński zagroził Spartanom: 'Jeśli wkroczę do Lakonii, zrównam ją z ziemią'. Odpowiedź: 'Jeśli'.", category: "ogólne", difficulty: "beginner" },
  { id: "17", word: "Makiawelizm", partOfSpeech: "rzeczownik", definition: "Bezwzględność w dążeniu do celu; polityka pozbawiona skrupułów moralnych. Termin pochodzi od Niccolò Machiavellego, autora 'Księcia', który opisał mechanizmy władzy bez moralizowania. Makiawelizm jest też cechą osobowości badaną w psychologii.", example: "1. Makiawelizm szefa firmy przerażał pracowników — manipulował i dzielił zespół.\n2. W psychologii makiawelizm to jedna z cech 'ciemnej triady' obok narcyzmu i psychopatii.", etymology: "od Niccolò Machiavelli", category: "ogólne", difficulty: "intermediate" },
  { id: "19", word: "Nepotyzm", partOfSpeech: "rzeczownik", definition: "Faworyzowanie krewnych i znajomych przy obsadzaniu stanowisk, bez względu na ich kompetencje. Termin pochodzi od łacińskiego nepos (siostrzeniec) — papieże często obsadzali krewnych na intratnych stanowiskach. Nepotyzm podważa merytokrację i zaufanie publiczne.", example: "1. Nepotyzm w tej instytucji był powszechnie znany — połowa kadry to kuzyni dyrektora.\n2. Średniowieczni papieże uprawiali nepotyzm na wielką skalę, mianując krewnych kardynałami.", category: "ogólne", difficulty: "beginner" },
  { id: "20", word: "Nonszalancja", partOfSpeech: "rzeczownik", definition: "Swobodne, lekceważące zachowanie; brak skrępowania i dbałości o konwenanse. Nonszalancja może wyrażać pewność siebie lub arogancję — zależy od kontekstu. W modzie nonszalancja jest ceniona jako wyraz naturalnej elegancji.", example: "1. Z nonszalancją odrzucił wszystkie propozycje, jakby nie obchodziło go ich zdanie.\n2. Jej nonszalancki styl ubierania — luźny sweter i potargane włosy — zachwycał fotografów mody.", category: "ogólne", difficulty: "beginner" },
  { id: "21", word: "Obskurantyzm", partOfSpeech: "rzeczownik", definition: "Wrogość wobec postępu, oświaty i wolnej myśli; celowe utrzymywanie ludzi w ciemnocie. Obskuranci uważają wiedzę za zagrożenie dla istniejącego porządku. Termin zrodził się w epoce Oświecenia jako określenie wrogów rozumu.", example: "1. Obskurantyzm tamtych czasów hamował rozwój nauki — Galileusz musiał odwołać swoje odkrycia.\n2. Cenzura internetu bywa formą współczesnego obskurantyzmu.", category: "ogólne", difficulty: "advanced" },
  { id: "22", word: "Ostentacyjny", partOfSpeech: "przymiotnik", definition: "Robiony na pokaz, demonstracyjny, manifestacyjny; mający na celu zwrócenie na siebie uwagi. Ostentacja polega na celowym, często przesadnym okazywaniu czegoś — bogactwa, emocji, poglądów. Jest blisko spokrewniona z ekshibicjonizmem społecznym.", example: "1. Ostentacyjnie odwrócił się plecami do mówcy, by pokazać swoje niezadowolenie.\n2. Jej ostentacyjna konsumpcja — złote zegarki, luksusowe auta — irytowała sąsiadów.", category: "ogólne", difficulty: "beginner" },
  { id: "24", word: "Parweniusz", partOfSpeech: "rzeczownik", definition: "Osoba, która szybko się wzbogaciła i naśladuje wyższe sfery, nie mając ich ogłady. Parweniusz często przesadza w demonstrowaniu statusu, co zdradza jego niedawny awans społeczny. Termin niesie zabarwienie lekceważące.", example: "1. Zachowywał się jak typowy parweniusz — kupował dzieła sztuki, nie rozumiejąc ich.\n2. Nowo bogaci oligarchowie lat 90. byli postrzegani jako parweniusze przez starą inteligencję.", etymology: "z fr. parvenu — ktoś, kto doszedł", category: "ogólne", difficulty: "intermediate" },
  { id: "25", word: "Pejoratywny", partOfSpeech: "przymiotnik", definition: "Mający ujemne zabarwienie emocjonalne; uwłaczający, pogardliwy, nacechowany negatywnie. W językoznawstwie pejoratywizacja to proces, w którym neutralne słowo zyskuje negatywne konotacje. Przeciwieństwem jest amelioratywność.", example: "1. Użył pejoratywnego określenia, co wywołało oburzenie zebranych.\n2. Słowo 'baba' przeszło pejoratywizację — kiedyś neutralne, dziś bywa obraźliwe.", category: "ogólne", difficulty: "intermediate" },
  { id: "26", word: "Permanentny", partOfSpeech: "przymiotnik", definition: "Trwały, ciągły, nieustanny — utrzymujący się bez przerwy przez dłuższy czas. Permanentność może dotyczyć zarówno stanów pozytywnych (permanentny rozwój), jak i negatywnych (permanentny stres). W filozofii Whiteheada permanentność jest iluzją — wszystko jest procesem.", example: "1. Permanentny brak snu odbijał się na jego zdrowiu i zdolności koncentracji.\n2. Permanentna rewolucja to koncepcja Trockiego — ciągła walka o zmianę społeczną.", category: "ogólne", difficulty: "beginner" },
  { id: "28", word: "Prokrastynacja", partOfSpeech: "rzeczownik", definition: "Nawykowe odkładanie działań na później, mimo świadomości negatywnych konsekwencji. Prokrastynacja nie jest lenistwem — to problem z regulacją emocji, nie z zarządzaniem czasem. Badania pokazują, że dotyka nawet 20% dorosłej populacji w sposób chroniczny.", example: "1. Prokrastynacja to plaga współczesnych studentów — pisanie prac naukowych w noc przed terminem.\n2. Pokonał prokrastynację, dzieląc wielkie zadania na małe, pięciominutowe kroki.", category: "ogólne", difficulty: "beginner" },
  { id: "29", word: "Redundancja", partOfSpeech: "rzeczownik", definition: "Nadmiar, zbędne powtórzenia; nadmiarowość informacji, która nie wnosi nowej treści. W informatyce redundancja jest pożądana — kopie zapasowe chronią przed utratą danych. W języku redundancja bywa zarówno wadą (gadulstwo), jak i zabezpieczeniem (powtórzenie dla jasności).", example: "1. Redundancja w jego tekście utrudniała lekturę — powtarzał to samo innymi słowami.\n2. Redundancja systemów lotniczych sprawia, że awaria jednego elementu nie kończy się katastrofą.", category: "ogólne", difficulty: "intermediate" },
  { id: "30", word: "Relikwia", partOfSpeech: "rzeczownik", definition: "Szczątki lub przedmioty związane ze świętym, otaczane kultem religijnym. Przenośnie — cenny zabytek, pamiątka z przeszłości przechowywana z pietyzmem. W średniowieczu handel relikwiami był źródłem ogromnych dochodów.", example: "1. Ten zegarek to rodzinna relikwia przekazywana od pokoleń — pamiątka po pradziadku.\n2. Katedra w Kolonii przechowuje relikwie Trzech Króli w złotym relikwiarzu.", category: "ogólne", difficulty: "beginner" },
  { id: "31", word: "Sentymentalny", partOfSpeech: "przymiotnik", definition: "Skłonny do czułostkowości, nadmiernie uczuciowy, rozrzewniony. Sentymentalizm może być szczery lub sztuczny — granica bywa cienka. W literaturze sentymentalizm był odrębnym nurtem XVIII wieku, kładącym nacisk na uczucia.", example: "1. Przy starych zdjęciach stawał się sentymentalny — łzy napływały mu do oczu.\n2. Sentymentalna muzyka lat 80. wciąż wzbudza nostalgię u pokolenia X.", category: "ogólne", difficulty: "beginner" },
  { id: "33", word: "Subtelny", partOfSpeech: "przymiotnik", definition: "Delikatny, wyrafinowany, trudny do uchwycenia — wymagający wyczulonych zmysłów lub umysłu. Subtelność bywa oznaką wysokiej kultury i inteligencji. W naukach ścisłych subtelne efekty to te, które łatwo przeoczyć, a które mogą mieć ogromne znaczenie.", example: "1. Subtelna różnica między tymi odcieniami niebieskiego była ledwo zauważalna.\n2. Jej subtelny humor — oparty na niedopowiedzeniu — doceniali tylko najbystrzejsi.", category: "ogólne", difficulty: "beginner" },
  { id: "34", word: "Sybarycki", partOfSpeech: "przymiotnik", definition: "Związany z przepychem, luksusem i wyrafinowanymi przyjemnościami; hedonistyczny. Nazwa pochodzi od starożytnych Sybarytów — mieszkańców greckiej kolonii Sybaris, słynących z rozpustnego życia. Sybarycki tryb życia kojarzy się z nadmiarem i brakiem umiaru.", example: "1. Prowadził sybarycki tryb życia — jedwabna pościel, śniadania z szampanem.\n2. Sybaryckie uczty starożytnych Rzymian trwały całymi dniami i obejmowały dziesiątki dań.", etymology: "od Sybarytów — mieszkańców starożytnego Sybaris", category: "ogólne", difficulty: "advanced" },
  { id: "37", word: "Ubikwitarny", partOfSpeech: "przymiotnik", definition: "Wszechobecny, spotykany wszędzie, przenikający każdy aspekt rzeczywistości. W biologii opisuje organizmy żyjące w różnorodnych środowiskach. W mowie potocznej odnosi się do zjawisk, które stały się nieodłączną częścią codzienności.", example: "1. Smartfony stały się ubikwitarne w codziennym życiu — trudno spotkać kogoś bez nich.\n2. Plastik jest materiałem ubikwitarnym — znajdziemy go nawet na dnie Rowu Mariańskiego.", category: "ogólne", difficulty: "advanced" },
  { id: "39", word: "Wielomówność", partOfSpeech: "rzeczownik", definition: "Skłonność do mówienia zbyt wiele; gadatliwość, która często nie idzie w parze z treściwością. Wielomówność bywa maskowana za erudycję, ale w istocie rozcieńcza przekaz. Przeciwieństwem jest lakoniczność.", example: "1. Jego wielomówność zniechęcała rozmówców — mówił godzinami, nie powiedziawszy nic.\n2. Wielomówność polityków przed wyborami kontrastuje z ich milczeniem po objęciu urzędu.", category: "ogólne", difficulty: "beginner" },
  { id: "40", word: "Xenofobia", partOfSpeech: "rzeczownik", definition: "Niechęć, wrogość lub lęk wobec obcych, cudzoziemców i tego, co nieznane. Xenofobia ma korzenie ewolucyjne — nieufność wobec obcych chroniła grupy plemienne. Współcześnie prowadzi do dyskryminacji, przemocy i podziałów społecznych.", example: "1. Xenofobia jest problemem społecznym w wielu krajach — szczególnie nasila się w czasach kryzysu.\n2. Kampanie antyxenofobiczne próbują zmienić postawy przez edukację i kontakt między kulturami.", category: "ogólne", difficulty: "beginner" },
  { id: "41", word: "Abnegacja", partOfSpeech: "rzeczownik", definition: "Wyrzeczenie się, zaniedbywanie własnych potrzeb i wyglądu; brak dbałości o siebie. Abnegacja może być świadomym wyborem (asceza) lub oznaką problemów psychicznych. W mowie potocznej odnosi się głównie do zaniedbania wyglądu.", example: "1. Jego abnegacja w kwestii ubioru była legendarna — nosił te same buty przez dziesięć lat.\n2. Geniusz naukowy i abnegacja życiowa szły u niego w parze — laboratorium było mu domem.", category: "ogólne", difficulty: "intermediate" },
  { id: "43", word: "Deprecjacja", partOfSpeech: "rzeczownik", definition: "Spadek wartości; umniejszanie, pomniejszanie znaczenia czegoś lub kogoś. W ekonomii deprecjacja oznacza spadek wartości waluty lub aktywów z biegiem czasu. W relacjach międzyludzkich deprecjacja to toksyczne zachowanie polegające na systematycznym umniejszaniu drugiej osoby.", example: "1. Deprecjacja waluty uderzyła w oszczędności obywateli — za te same pieniądze kupili mniej.\n2. Ciągła deprecjacja jej osiągnięć przez partnera była formą przemocy emocjonalnej.", category: "ogólne", difficulty: "intermediate" },
  { id: "45", word: "Fetyszyzm", partOfSpeech: "rzeczownik", definition: "Przypisywanie nadmiernego, irracjonalnego znaczenia przedmiotom, symbolom lub pojęciom. Pierwotnie termin opisywał afrykańskie wierzenia w magiczną moc przedmiotów. Marks użył go do opisania 'fetyszyzmu towarowego' — traktowania rzeczy jak bytów posiadających magiczną wartość.", example: "1. Fetyszyzm technologiczny sprawia, że gubimy to, co naprawdę ważne — relacje z ludźmi.\n2. Marks opisywał fetyszyzm towarowy jako iluzję, że wartość tkwi w samym przedmiocie.", category: "ogólne", difficulty: "intermediate" },
  { id: "48", word: "Inklinacja", partOfSpeech: "rzeczownik", definition: "Skłonność, tendencja do czegoś; naturalne upodobanie lub zamiłowanie. Inklinacja bywa wrodzona lub kształtowana przez doświadczenie i środowisko. W fizyce to kąt nachylenia — co pięknie oddaje metaforę 'pochylania się ku czemuś'.", example: "1. Od dziecka miał inklinację do nauk ścisłych — rozbierał zegarki i składał je z powrotem.\n2. Jej inklinacja do samotności nie oznaczała mizantropii — po prostu potrzebowała ciszy.", category: "ogólne", difficulty: "intermediate" },
  { id: "o11", word: "Konformista", partOfSpeech: "rzeczownik", definition: "Osoba bezrefleksyjnie dostosowująca się do obowiązujących norm, opinii i zachowań grupy. Konformista unika konfliktu za cenę rezygnacji z własnego zdania. Eksperymenty Ascha pokazały, jak silna jest presja konformizmu — ludzie potrafią zaprzeczać własnym oczom.", example: "1. Był konformistą — nigdy nie wyraził zdania sprzecznego z opinią szefa.\n2. W totalitarnych systemach konformiści stanowili trzon społeczeństwa — milcząca większość.", category: "ogólne", difficulty: "beginner" },
  { id: "o12", word: "Mizantropia", partOfSpeech: "rzeczownik", definition: "Niechęć do ludzi; pogarda wobec natury ludzkiej i unikanie kontaktów społecznych. Mizantrop nie musi być zły — często to osoba głęboko rozczarowana ludźmi. Molière napisał komedię 'Mizantrop', w której główny bohater jest uczciwy do granic absurdu.", example: "1. Jego mizantropia narastała z wiekiem — w końcu zamieszkał sam na wsi z psami.\n2. Mizantropia Schopenhauera wyrażała się w filozofii pełnej pesymizmu wobec natury ludzkiej.", etymology: "z gr. misanthropos — nienawidzący ludzi", category: "ogólne", difficulty: "intermediate" },
  { id: "o13", word: "Egalitarny", partOfSpeech: "przymiotnik", definition: "Głoszący równość społeczną i polityczną wszystkich ludzi, bez względu na pochodzenie czy status. Ideały egalitarne leżą u podstaw demokracji i praw człowieka. W praktyce pełna egalitarność jest trudna do osiągnięcia.", example: "1. Skandynawskie społeczeństwa uchodzą za jedne z najbardziej egalitarnych na świecie.\n2. Egalitarne podejście w szkole zakładało, że każde dziecko zasługuje na takie same szanse.", category: "ogólne", difficulty: "intermediate" },

  // ===== PSYCHOLOGIA =====
  { id: "p1", word: "Kognitywny", partOfSpeech: "przymiotnik", definition: "Dotyczący poznania, procesów myślowych i umysłowych. Psychologia kognitywna bada, jak ludzie spostrzegają, zapamiętują, myślą i rozwiązują problemy. Terapia kognitywna pomaga zmieniać dysfunkcjonalne wzorce myślenia.", example: "1. Terapia kognitywna pomaga zmienić negatywne wzorce myślenia na bardziej realistyczne.\n2. Kognitywne zniekształcenia, jak katastrofizowanie, pogarszają samopoczucie bez realnych podstaw.", etymology: "z łac. cognitio — poznanie", category: "psychologia", difficulty: "beginner" },
  { id: "p2", word: "Dysocjacja", partOfSpeech: "rzeczownik", definition: "Rozłączenie procesów psychicznych; oderwanie od rzeczywistości, ciała lub tożsamości. Dysocjacja jest mechanizmem obronnym w traumatycznych sytuacjach — umysł 'wyłącza się', by przetrwać. Może przejawiać się od łagodnego 'odpływania myślami' po poważne zaburzenia tożsamości.", example: "1. Dysocjacja podczas wypadku sprawiła, że obserwowała siebie jakby z zewnątrz.\n2. Chroniczna dysocjacja po traumie może prowadzić do poczucia, że żyje się we śnie.", category: "psychologia", difficulty: "intermediate" },
  { id: "p3", word: "Katharsis", partOfSpeech: "rzeczownik", definition: "Oczyszczenie emocjonalne przez przeżycie silnych uczuć, takich jak strach czy litość. Arystoteles uważał, że tragedia teatralna prowadzi do katharsis widza — uwalnia tłumione emocje. Współcześnie termin jest używany w psychoterapii i kulturze popularnej.", example: "1. Oglądanie tragedii greckiej miało prowadzić do katharsis — oczyszczenia duszy widza.\n2. Po latach terapii poczuła katharsis — mogła wreszcie mówić o traumie bez bólu.", etymology: "z gr. katharsis — oczyszczenie", category: "psychologia", difficulty: "intermediate" },
  { id: "p4", word: "Sublimacja", partOfSpeech: "rzeczownik", definition: "Mechanizm obronny polegający na przekształcaniu nieakceptowanych popędów w działania społecznie aprobowane i twórcze. Freud uważał sublimację za najzdrowszy sposób radzenia sobie z popędami. Wielu artystów sublimowało swoje cierpienie w wielkie dzieła.", example: "1. Jego agresję sublimował poprzez intensywne treningi bokserskie — ring zastąpił ulicę.\n2. Beethoven sublimował samotność i cierpienie w muzykę, która porusza miliony ludzi.", category: "psychologia", difficulty: "intermediate" },
  { id: "p5", word: "Projekcja", partOfSpeech: "rzeczownik", definition: "Mechanizm obronny polegający na przypisywaniu innym własnych nieakceptowanych uczuć, myśli lub motywów. Projekcja chroni ego przed konfrontacją z nieprzyjemnymi prawdami o sobie. Jest jednym z najczęstszych mechanizmów obronnych opisanych przez Freuda.", example: "1. Oskarżanie wszystkich o kłamstwo było jego projekcją — sam nie potrafił być szczery.\n2. Osoba zazdrosna może projektować swoją zazdrość na partnera, oskarżając go o niewierność.", category: "psychologia", difficulty: "beginner" },
  { id: "p6", word: "Afekt", partOfSpeech: "rzeczownik", definition: "Krótkotrwały, gwałtowny stan emocjonalny o dużym natężeniu, często prowadzący do impulsywnych działań. Afekt różni się od emocji siłą i nagłością — jest jak eksplozja uczuć. W prawie 'działanie w afekcie' jest okolicznością łagodzącą.", example: "1. Działał w afekcie i później żałował swoich słów — nie panował nad sobą.\n2. W stanie afektu ludzie potrafią dokonać czynów, których normalnie by się nie podjęli.", category: "psychologia", difficulty: "beginner" },
  { id: "p7", word: "Ambiwalencja", partOfSpeech: "rzeczownik", definition: "Jednoczesne odczuwanie sprzecznych emocji wobec tego samego obiektu — np. miłości i nienawiści. Ambiwalencja jest naturalną częścią ludzkiego doświadczenia, choć bywa trudna do zniesienia. Bleuer wprowadził ten termin do psychiatrii na początku XX wieku.", example: "1. Ambiwalencja wobec matki jest częstym tematem w psychoanalizie — kochamy i złościmy się jednocześnie.\n2. Czuł ambiwalencję wobec awansu — chciał go, ale bał się nowej odpowiedzialności.", category: "psychologia", difficulty: "intermediate" },
  { id: "p8", word: "Introspekcja", partOfSpeech: "rzeczownik", definition: "Obserwowanie i analizowanie własnych przeżyć psychicznych, myśli i uczuć. Introspekcja była pierwszą metodą psychologii naukowej, zanim zastąpił ją behawioryzm. Współcześnie docenia się ją jako element mindfulness i samoświadomości.", example: "1. Filozofowie zachęcali do introspekcji jako drogi do samowiedzy — 'poznaj samego siebie'.\n2. Prowadzenie dziennika to forma introspekcji, która pomaga zrozumieć własne wzorce zachowań.", category: "psychologia", difficulty: "intermediate" },
  { id: "p9", word: "Empatia", partOfSpeech: "rzeczownik", definition: "Zdolność wczuwania się w stany emocjonalne innych osób; rozumienie ich uczuć i perspektywy. Empatia dzieli się na poznawczą (rozumiem, co czujesz) i emocjonalną (czuję to, co ty). Jest fundamentem relacji międzyludzkich i kluczową kompetencją w zawodach pomocowych.", example: "1. Empatia jest kluczowa w pracy terapeuty — bez niej nie można zbudować zaufania.\n2. Brak empatii nie zawsze oznacza złośliwość — osoby z aleksytymią po prostu nie rozpoznają emocji.", category: "psychologia", difficulty: "beginner" },
  { id: "p10", word: "Neurotyzm", partOfSpeech: "rzeczownik", definition: "Cecha osobowości wyrażająca skłonność do przeżywania negatywnych emocji, takich jak lęk, smutek i irytacja. Neurotyzm jest jednym z pięciu wielkich czynników osobowości (Big Five). Osoby o wysokim neurotyzmie silniej reagują na stres, ale bywają też bardziej twórcze.", example: "1. Wysoki neurotyzm wiąże się z podatnością na lęk i depresję, ale też z wrażliwością artystyczną.\n2. Badania pokazują, że neurotyzm częściowo dziedziczymy — geny odpowiadają za ok. 40% zmienności.", category: "psychologia", difficulty: "intermediate" },
  { id: "p11", word: "Katatonia", partOfSpeech: "rzeczownik", definition: "Stan bezruchu i braku reakcji na bodźce zewnętrzne, często towarzyszący ciężkim zaburzeniom psychicznym. Osoba w katatonii może utrzymywać nienaturalne pozycje ciała przez godziny. Katatonia może się też objawiać nadmiernym, bezcelowym pobudzeniem ruchowym.", example: "1. Pacjent popadł w katatonię i nie reagował na otoczenie przez wiele godzin.\n2. Katatonia paradoksalnie może przybierać formę ekstremalnego pobudzenia — pacjent biega i krzyczy bez celu.", category: "psychologia", difficulty: "advanced" },
  { id: "p12", word: "Konfabulacja", partOfSpeech: "rzeczownik", definition: "Nieświadome wypełnianie luk pamięciowych zmyślonymi, ale wiarygodnymi treściami. Konfabulacja nie jest kłamstwem — osoba szczerze wierzy w to, co mówi. Typowa dla zespołu Korsakowa, uszkodzeń mózgu i niektórych demencji.", example: "1. Konfabulacje są typowe dla zespołu Korsakowa — pacjent opowiada szczegółowo o wydarzeniach, które nigdy nie miały miejsca.\n2. Dziadek konfabulował o swoim dniu — twierdził, że chodził do pracy, choć od lat był na emeryturze.", category: "psychologia", difficulty: "advanced" },
  { id: "p13", word: "Egocentryzm", partOfSpeech: "rzeczownik", definition: "Tendencja do postrzegania świata wyłącznie z własnej perspektywy, trudność w przyjęciu punktu widzenia innej osoby. Egocentryzm u małych dzieci jest naturalnym etapem rozwoju poznawczego — z wiekiem zanika. U dorosłych może być oznaką niedojrzałości emocjonalnej.", example: "1. Egocentryzm u małych dzieci jest naturalny — trzylatek nie rozumie, że inni widzą świat inaczej.\n2. Egocentryzm dorosłego przejawiał się tym, że każdą rozmowę sprowadzał do swoich problemów.", category: "psychologia", difficulty: "beginner" },
  { id: "p14", word: "Racjonalizacja", partOfSpeech: "rzeczownik", definition: "Mechanizm obronny polegający na wymyślaniu logicznych, akceptowalnych uzasadnień dla irracjonalnych zachowań lub decyzji. Racjonalizacja chroni przed poczuciem winy i wstydu — 'to było rozsądne' zamiast 'bałem się'. Jest tak powszechna, że często nie zdajemy sobie z niej sprawy.", example: "1. Racjonalizacja pozwalała mu unikać konfrontacji z prawdziwymi motywami — 'nie chciałem jej skrzywdzić' zamiast 'bałem się'.\n2. 'I tak nie chciałam tej pracy' — klasyczna racjonalizacja po odrzuceniu kandydatury.", category: "psychologia", difficulty: "beginner" },
  { id: "p15", word: "Habituacja", partOfSpeech: "rzeczownik", definition: "Stopniowe przyzwyczajanie się do powtarzającego się bodźca i spadek reakcji na niego. Habituacja jest jedną z najprostszych form uczenia się, występującą nawet u organizmów jednokomórkowych. Pozwala odfiltrować nieistotne informacje i skupić się na tym, co nowe.", example: "1. Habituacja sprawia, że przestajemy słyszeć tykanie zegara po kilku minutach.\n2. Mieszkańcy przy ruchliwej ulicy ulegają habituacji — po tygodniu hałas im nie przeszkadza.", category: "psychologia", difficulty: "intermediate" },
  { id: "p16", word: "Anhedonia", partOfSpeech: "rzeczownik", definition: "Niezdolność do odczuwania przyjemności z aktywności, które wcześniej ją sprawiały. Anhedonia jest jednym z głównych objawów depresji i schizofrenii. Może dotyczyć zarówno przyjemności fizycznych (jedzenie, seks), jak i społecznych (kontakty z ludźmi).", example: "1. Anhedonia jest jednym z głównych objawów depresji — ulubione hobby nagle traci smak.\n2. Odkąd popadł w anhedonię, nawet spotkania z przyjaciółmi nie sprawiały mu radości.", category: "psychologia", difficulty: "intermediate" },
  { id: "p17", word: "Apofenia", partOfSpeech: "rzeczownik", definition: "Tendencja do dostrzegania wzorców, połączeń i znaczeń w losowych, niezwiązanych ze sobą danych. Apofenia jest cechą ludzkiego mózgu, który ewolucyjnie wykształcił się, by szukać wzorców — nawet tam, gdzie ich nie ma. Może prowadzić zarówno do twórczych odkryć, jak i teorii spiskowych.", example: "1. Apofenia sprawia, że widzimy twarze w chmurach i postacie w plamach na ścianie.\n2. Nadmierna apofenia może prowadzić do teorii spiskowych — wszędzie widzi się ukryte powiązania.", category: "psychologia", difficulty: "advanced" },
  { id: "p18", word: "Resiliencja", partOfSpeech: "rzeczownik", definition: "Odporność psychiczna; zdolność do radzenia sobie z trudnościami, traumą i stresem oraz powrotu do równowagi. Resiliencja nie oznacza braku cierpienia — raczej umiejętność adaptacji mimo cierpienia. Można ją rozwijać przez budowanie relacji, elastyczność myślenia i poczucie sensu.", example: "1. Resiliencja dzieci z trudnych środowisk zaskakiwała badaczy — niektóre rozwijały się prawidłowo mimo traumy.\n2. Budowanie resiliencji wymaga silnych relacji, elastyczności i poczucia, że życie ma sens.", category: "psychologia", difficulty: "intermediate" },
  { id: "p19", word: "Konformizm", partOfSpeech: "rzeczownik", definition: "Dostosowywanie swoich poglądów i zachowań do norm grupy, często wbrew własnemu przekonaniu. Eksperymenty Ascha pokazały, że ludzie potrafią zaprzeczać oczywistym faktom pod presją grupy. Konformizm ma funkcje adaptacyjne, ale może prowadzić do utraty tożsamości.", example: "1. Eksperyment Ascha udowodnił siłę konformizmu — ludzie twierdzili, że krótka linia jest dłuższa, bo tak mówili inni.\n2. Konformizm w pracy bywa formą przetrwania — niezgadzanie się z szefem kończy się zwolnieniem.", category: "psychologia", difficulty: "beginner" },
  { id: "p20", word: "Aleksytymia", partOfSpeech: "rzeczownik", definition: "Trudność w identyfikowaniu, opisywaniu i przeżywaniu własnych emocji. Osoby z aleksytymią nie są pozbawione emocji — po prostu nie mają do nich świadomego dostępu. Aleksytymia dotyka ok. 10% populacji i wiąże się z większym ryzykiem chorób psychosomatycznych.", example: "1. Osoby z aleksytymią mają problem z wyrażaniem uczuć słowami — pytane 'co czujesz?', odpowiadają 'nie wiem'.\n2. Aleksytymia utrudnia terapię — pacjent dosłownie nie potrafi powiedzieć, co go boli emocjonalnie.", category: "psychologia", difficulty: "advanced" },
  { id: "p21", word: "Paradygmat", partOfSpeech: "rzeczownik", definition: "Przyjęty model myślenia i interpretowania rzeczywistości w danej dziedzinie nauki. Thomas Kuhn opisał, jak rewolucje naukowe polegają na zmianie paradygmatu — zastąpieniu starego modelu nowym. Zmiana paradygmatu to fundamentalna zmiana perspektywy.", example: "1. Rewolucja behawioralna zmieniła paradygmat w psychologii — z introspekcji na obserwację zachowania.\n2. Przejście z geocentryzmu do heliocentryzmu było klasyczną zmianą paradygmatu.", category: "psychologia", difficulty: "intermediate" },
  { id: "p22", word: "Deprywacja", partOfSpeech: "rzeczownik", definition: "Pozbawienie lub ograniczenie zaspokojenia podstawowych potrzeb — fizycznych, emocjonalnych lub społecznych. Deprywacja sensoryczna (brak bodźców) prowadzi do halucynacji, a deprywacja emocjonalna u dzieci — do poważnych zaburzeń rozwojowych. Eksperymenty z deprywacją pokazały fundamentalne potrzeby człowieka.", example: "1. Deprywacja sensoryczna po 48 godzinach prowadzi do halucynacji — mózg sam tworzy bodźce.\n2. Deprywacja emocjonalna w dzieciństwie może skutkować zaburzeniami przywiązania przez całe życie.", category: "psychologia", difficulty: "intermediate" },
  { id: "p23", word: "Heurystyka", partOfSpeech: "rzeczownik", definition: "Uproszczona reguła myślenia stosowana przy podejmowaniu decyzji, pozwalająca szybko, choć nie zawsze trafnie, dojść do wniosku. Heurystyki są 'skrótami umysłowymi' — oszczędzają czas kosztem precyzji. Kahneman i Tversky opisali wiele systematycznych błędów wynikających z heurystyk.", example: "1. Heurystyka dostępności sprawia, że przeceniamy ryzyko ataków rekinów — bo pamiętamy o nich z mediów.\n2. Heurystyka zakotwiczenia powoduje, że pierwsza podana cena wpływa na negocjacje, nawet jeśli jest absurdalna.", category: "psychologia", difficulty: "intermediate" },
  { id: "p24", word: "Dysforia", partOfSpeech: "rzeczownik", definition: "Stan niezadowolenia, niepokoju i ogólnego dyskomfortu psychicznego — przeciwieństwo euforii. Dysforia może towarzyszyć wielu zaburzeniom psychicznym, ale też naturalnym stanom jak PMS. Dysforia płciowa oznacza rozbieżność między odczuwaną a przypisaną płcią.", example: "1. Dysforia towarzyszyła jej przez cały okres adaptacji w nowym mieście — nic nie cieszyło.\n2. Dysforia płciowa to poważne cierpienie wymagające wsparcia specjalistów, nie lekceważenia.", category: "psychologia", difficulty: "intermediate" },
  { id: "p25", word: "Pareidolia", partOfSpeech: "rzeczownik", definition: "Skłonność do postrzegania znanych wzorców (zwłaszcza twarzy) w losowych obiektach i układach. Pareidolia jest odmianą apofenii i wynika z ewolucyjnego 'nastawienia na twarze' — lepiej raz za dużo dostrzec twarz niż przeoczyć prawdziwe zagrożenie. Stąd widzimy twarze w gniazdkach elektrycznych i chmurach.", example: "1. Pareidolia tłumaczy, dlaczego widzimy twarz na powierzchni Marsa — i w każdym gniazdku.\n2. Dzięki pareidolii pralka z dwoma okrągłymi guziczkami 'wygląda jak buzia'.", category: "psychologia", difficulty: "intermediate" },
  { id: "p26", word: "Atrybukcja", partOfSpeech: "rzeczownik", definition: "Proces przypisywania przyczyn zachowaniom — własnym i innych osób. Ludzie mają tendencję do wyjaśniania zachowań innych cechami osobowości (atrybucja wewnętrzna), a swoich — sytuacją (atrybucja zewnętrzna). Ten asymetryczny wzorzec nazywamy fundamentalnym błędem atrybucji.", example: "1. Fundamentalny błąd atrybucji polega na przecenianiu cech osobowości — 'spóźnił się, bo jest nieodpowiedzialny' (a może miał korki).\n2. Gdy sami się spóźniamy, stosujemy atrybucję sytuacyjną — 'autobus się spóźnił', nigdy 'jestem nieodpowiedzialny'.", category: "psychologia", difficulty: "intermediate" },
  { id: "p27", word: "Dysonans poznawczy", partOfSpeech: "rzeczownik", definition: "Napięcie psychiczne wynikające z posiadania sprzecznych przekonań, postaw lub zachowań niezgodnych z przekonaniami. Dysonans poznawczy odkrył Leon Festinger — ludzie redukują go, zmieniając przekonania, zachowanie lub racjonalizując sprzeczność. Jest jedną z najważniejszych koncepcji psychologii społecznej.", example: "1. Palacz świadomy szkodliwości tytoniu doświadcza dysonansu poznawczego — wie, że powinien rzucić.\n2. Po kupnie drogiego auta ludzie szukają potwierdzenia słuszności decyzji — to redukcja dysonansu.", category: "psychologia", difficulty: "beginner" },
  { id: "p28", word: "Kompensacja", partOfSpeech: "rzeczownik", definition: "Mechanizm obronny polegający na wyrównywaniu braków w jednej dziedzinie osiągnięciami w innej. Adler uważał kompensację za podstawowy mechanizm napędzający rozwój człowieka — poczucie niższości motywuje do doskonalenia się. Kompensacja może być zdrowa (sport zamiast agresji) lub niezdrowa (pracoholizm zamiast relacji).", example: "1. Jego nadmierna pracowitość była kompensacją poczucia niższości — 'jeśli będę najlepszy, wreszcie mnie zaakceptują'.\n2. Demostenes kompensował wadę wymowy intensywnymi ćwiczeniami — i stał się najsłynniejszym mówcą starożytności.", category: "psychologia", difficulty: "beginner" },
  { id: "p29", word: "Somatyzacja", partOfSpeech: "rzeczownik", definition: "Przejawianie się problemów psychicznych w formie objawów cielesnych — bólów, nudności, zmęczenia. Ciało 'mówi' tym, czego umysł nie potrafi wyrazić słowami. Somatyzacja jest szczególnie częsta u dzieci i w kulturach, gdzie mówienie o emocjach jest tabu.", example: "1. Ból brzucha dziecka okazał się somatyzacją lęku szkolnego — badania nie wykazały przyczyn fizycznych.\n2. Po rozwodzie doświadczał chronicznego bólu pleców — lekarze podejrzewali somatyzację stresu.", category: "psychologia", difficulty: "advanced" },
  { id: "p30", word: "Ruminacja", partOfSpeech: "rzeczownik", definition: "Natarczywe, powtarzające się rozpamiętywanie negatywnych myśli i wydarzeń, jak kręcenie się w kółko bez wyjścia. Ruminacja pogłębia depresję — zamiast szukać rozwiązań, osoba roztrząsa problemy w nieskończoność. Termin pochodzi od przeżuwania — jak krowa przeżuwa trawę, tak umysł 'przeżuwa' myśli.", example: "1. Ruminacja pogłębiała jej stany depresyjne — leżała w łóżku, analizując każdy błąd z przeszłości.\n2. Terapia kognitywna uczy przerywania ruminacji — zamiast myśleć 'dlaczego?', pytać 'co mogę zrobić?'.", category: "psychologia", difficulty: "intermediate" },
  { id: "p31", word: "Introjekcja", partOfSpeech: "rzeczownik", definition: "Nieświadome przyswajanie sobie cudzych wartości, przekonań i postaw — 'wchłanianie' ich bez krytycznej analizy. Introjekcja jest ważnym mechanizmem w rozwoju superego — dziecko introjekcjuje normy rodziców. Problem pojawia się, gdy introjekcjowane normy są toksyczne.", example: "1. Introjekcja wartości rodzicielskich kształtuje superego — 'musisz być najlepszy' staje się wewnętrznym głosem.\n2. W terapii Gestalt pracuje się nad uświadomieniem introjekcji — rozpoznaniem, które przekonania są naprawdę nasze.", category: "psychologia", difficulty: "advanced" },
  { id: "p32", word: "Abulia", partOfSpeech: "rzeczownik", definition: "Chorobliwy brak woli, niezdolność do podejmowania decyzji i inicjowania działań. Abulia nie jest lenistwem — osoba chce działać, ale nie potrafi przekuć zamiaru w czyn. Towarzyszy uszkodzeniom płata czołowego mózgu, ciężkiej depresji i niektórym postaciom schizofrenii.", example: "1. Abulia uniemożliwiała mu wykonanie najprostszych czynności — nawet wstanie z łóżka było walką.\n2. Po udarze doświadczył abulii — chciał mówić, chciał jeść, ale sygnał z mózgu nie docierał do ciała.", category: "psychologia", difficulty: "advanced" },
  { id: "p33", word: "Depersonalizacja", partOfSpeech: "rzeczownik", definition: "Poczucie obcości wobec samego siebie — jakby obserwowało się własne życie z zewnątrz, zza szyby. Depersonalizacja jest częstym objawem lęku, traumy i przemęczenia. Choć przerażająca, jest nieszkodliwa — mózg 'dystansuje się' od przytłaczających emocji.", example: "1. Epizody depersonalizacji sprawiały, że czuł się jak obserwator własnego życia — nic nie wydawało się realne.\n2. Depersonalizacja podczas ataku paniki mija sama — to mechanizm obronny, nie choroba.", category: "psychologia", difficulty: "intermediate" },
  { id: "p35", word: "Metapoznanie", partOfSpeech: "rzeczownik", definition: "Myślenie o własnym myśleniu; świadomość i kontrola własnych procesów poznawczych. Metapoznanie pozwala ocenić, czy naprawdę rozumiemy materiał, czy tylko nam się tak wydaje. Jest kluczowe dla efektywnej nauki i samorozwoju.", example: "1. Metapoznanie pozwala uczniom efektywniej się uczyć — wiedzą, kiedy nie rozumieją.\n2. Brak metapoznania to efekt Dunninga-Krugera — ludzie nie wiedzą, jak mało wiedzą.", category: "psychologia", difficulty: "intermediate" },
  { id: "ps11", word: "Efekt aureoli", partOfSpeech: "rzeczownik", definition: "Tendencja do oceniania osoby na podstawie jednej wyrazistej cechy — np. atrakcyjności fizycznej. Jeśli ktoś jest przystojny, automatycznie przypisujemy mu też inteligencję i uczciwość. Efekt aureoli działa też w odwrotną stronę — jedno negatywne wrażenie zabarwia resztę.", example: "1. Efekt aureoli sprawia, że ładni ludzie są postrzegani jako bardziej kompetentni w rozmowach kwalifikacyjnych.\n2. Po jednym błędzie pracownika szef zaczął widzieć wyłącznie jego wady — odwrócony efekt aureoli.", category: "psychologia", difficulty: "beginner" },
  { id: "ps12", word: "Efekt Zeigarnik", partOfSpeech: "rzeczownik", definition: "Zjawisko lepszego pamiętania zadań niedokończonych niż ukończonych — mózg 'trzyma otwartą kartę' dla niedokończonych spraw. Odkryty przez Blumę Zeigarnik, uczennicę Kurta Lewina. Wykorzystywany w marketingu (cliffhangery) i produktywności (metoda 'zacznij, a skończysz').", example: "1. Efekt Zeigarnik tłumaczy, dlaczego niedokończony serial nie daje nam spokoju — musimy obejrzeć następny odcinek.\n2. Kelnerzy pamiętają niezrealizowane zamówienia — po podaniu posiłku natychmiast je zapominają.", category: "psychologia", difficulty: "intermediate" },
  { id: "ps13", word: "Gaslighting", partOfSpeech: "rzeczownik", definition: "Forma manipulacji psychicznej polegająca na podważaniu czyjegoś poczucia rzeczywistości — 'to ci się tylko wydaje', 'przesadzasz'. Termin pochodzi od filmu 'Gaslight' z 1944 roku. Gaslighting jest formą przemocy emocjonalnej, która powoli niszczy pewność siebie ofiary.", example: "1. Ciągłe mówienie 'jesteś zbyt wrażliwa' to gaslighting — podważa czyjeś prawo do emocji.\n2. Rozpoznanie gaslightingu jest trudne, bo ofiara zaczyna wątpić we własny zdrowy rozsądek.", category: "psychologia", difficulty: "beginner" },

  // ===== CIEKAWI LUDZIE (35) =====
  { id: "cl1", word: "Diogenes z Synopy", partOfSpeech: "postać historyczna", definition: "Grecki filozof-cynik, który żył w beczce i chodził z latarnią 'szukając człowieka'. Odrzucał wszelkie konwenanse społeczne.", example: "Gdy Aleksander Wielki zaproponował mu spełnienie życzenia, Diogenes odparł: 'Nie zasłaniaj mi słońca'.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl2", word: "Hipatia z Aleksandrii", partOfSpeech: "postać historyczna", definition: "Pierwsza znana kobieta-matematyczka i filozofka. Kierowała szkołą neoplatońską w Aleksandrii. Zamordowana przez tłum w 415 r.", example: "Hipatia wykładała filozofię, astronomię i matematykę w czasach, gdy kobiety nie miały głosu.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl3", word: "Nikola Tesla", partOfSpeech: "postać historyczna", definition: "Serbsko-amerykański wynalazca prądu zmiennego. Posiadał pamięć ejdetyczną i wizualizował maszyny w umyśle przed ich budową.", example: "Tesla twierdził, że odbiera sygnały z kosmosu — dziś uważa się, że słyszał pulsary.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl4", word: "Symeon Słupnik", partOfSpeech: "postać historyczna", definition: "Asceta chrześcijański, który spędził 37 lat na szczycie kolumny, modląc się i głosząc kazania do tłumów.", example: "Symeon Słupnik stał się symbolem skrajnej ascezy i oderwania od świata.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl5", word: "Ada Lovelace", partOfSpeech: "postać historyczna", definition: "Angielska matematyczka, uznawana za pierwszą programistkę w historii. Napisała algorytm dla maszyny analitycznej Babbage'a.", example: "Ada Lovelace przewidziała, że maszyny będą mogły komponować muzykę.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl6", word: "Rasputin", partOfSpeech: "postać historyczna", definition: "Rosyjski mistyk, który zdobył ogromny wpływ na rodzinę carską dzięki rzekomej zdolności leczenia hemofilii carewicza.", example: "Legenda głosi, że Rasputin przeżył truciznę, strzały i pobicie, zanim ostatecznie utonął.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl7", word: "Émilie du Châtelet", partOfSpeech: "postać historyczna", definition: "Francuska fizyczka i filozofka, która przetłumaczyła Newtona na francuski. Partnerka Voltaire'a i pionierka fizyki.", example: "Du Châtelet udowodniła, że energia kinetyczna jest proporcjonalna do kwadratu prędkości.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl8", word: "Tarrare", partOfSpeech: "postać historyczna", definition: "Francuski żołnierz z XVIII w. cierpiący na niewyobrażalny głód — jadł żywe koty, węże i próbował jeść ciała.", example: "Lekarze badali Tarrare'a, ale nigdy nie wyjaśnili przyczyny jego nienasyconego apetytu.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl9", word: "Hypatia Bradlaugh Bonner", partOfSpeech: "postać historyczna", definition: "Brytyjska pisarka i aktywistka ateistyczna, córka Charlesa Bradlaugha. Walczyła o prawa kobiet i wolność myśli.", example: "Bonner kontynuowała dzieło ojca, walcząc o świecki humanizm w Anglii.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl10", word: "Srinivasa Ramanujan", partOfSpeech: "postać historyczna", definition: "Indyjski matematyk-samouk, który bez formalnego wykształcenia odkrył tysiące twierdzeń. Twierdził, że wzory objawia mu bogini.", example: "Ramanujan wysłał list do Hardy'ego z Cambridge — ten uznał go za geniusza.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl11", word: "Casanova", partOfSpeech: "postać historyczna", definition: "Wenecki awanturnik, pisarz i dyplomata. Znany z licznych romansów, ale też z genialnej ucieczki z więzienia Piombi.", example: "Casanova był nie tylko uwodzicielem, ale też bibliotekarzem, szpiegiem i alchemikiem.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl12", word: "Mary Anning", partOfSpeech: "postać historyczna", definition: "Angielska paleontolożka-samouk, która odkryła pierwsze kompletne szkielety ichtiozaurów i plezjozaurów.", example: "Mary Anning zrewolucjonizowała paleontologię, choć jako kobieta nie mogła publikować pod własnym nazwiskiem.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl13", word: "Grigori Perelman", partOfSpeech: "postać historyczna", definition: "Rosyjski matematyk, który udowodnił hipotezę Poincarégo i odmówił przyjęcia miliona dolarów nagrody.", example: "Perelman zrezygnował z nagrody Fieldsa i żyje w odosobnieniu z matką w Petersburgu.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl14", word: "Ching Shih", partOfSpeech: "postać historyczna", definition: "Chińska piratka, która dowodziła flotą 1800 statków i 80 000 ludzi. Jedna z najgroźniejszych piratek w historii.", example: "Ching Shih negocjowała amnestię z cesarzem i zakończyła karierę jako właścicielka kasyna.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl15", word: "Alan Turing", partOfSpeech: "postać historyczna", definition: "Brytyjski matematyk, ojciec informatyki. Złamał szyfr Enigmy, ratując miliony. Prześladowany za homoseksualizm.", example: "Turing zaproponował test na inteligencję maszynową, który do dziś jest standardem.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl16", word: "Hildegarda z Bingen", partOfSpeech: "postać historyczna", definition: "Niemiecka benedyktynka, mistyczka, kompozytorka, lekarka i filozofka przyrody z XII wieku.", example: "Hildegarda napisała traktaty o medycynie naturalnej, komponowała muzykę i miała wizje mistyczne.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl17", word: "Tycho Brahe", partOfSpeech: "postać historyczna", definition: "Duński astronom, który stracił nos w pojedynku i nosił protezę ze złota. Miał łosia jako zwierzę domowe.", example: "Łoś Brahe'go zginął, spadając ze schodów po wypiciu zbyt dużo piwa na przyjęciu.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl18", word: "Hedy Lamarr", partOfSpeech: "postać historyczna", definition: "Austriacko-amerykańska aktorka i wynalazczyni. Opatentowała technologię przeskakiwania częstotliwości — bazę Wi-Fi i Bluetooth.", example: "Lamarr była gwiazdą Hollywood, ale jej wynalazek doceniono dopiero dekady później.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl19", word: "Ignaz Semmelweis", partOfSpeech: "postać historyczna", definition: "Węgierski lekarz, który odkrył, że mycie rąk ratuje życie. Wyśmiany przez środowisko medyczne, zmarł w szpitalu psychiatrycznym.", example: "Semmelweis zmniejszył śmiertelność na oddziałach położniczych o 90%, ale nikt mu nie wierzył.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl20", word: "Jeanne Baret", partOfSpeech: "postać historyczna", definition: "Pierwsza kobieta, która opłynęła świat — przebrała się za mężczyznę, by dołączyć do ekspedycji Bougainville'a.", example: "Baret zebrała tysiące okazów botanicznych podczas swojej podróży dookoła świata.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl21", word: "Nikołaj Fiodorow", partOfSpeech: "postać historyczna", definition: "Rosyjski filozof-kosmista, który wierzył w wskrzeszenie wszystkich zmarłych przodków za pomocą nauki.", example: "Fiodorow postulował kolonizację kosmosu jako moralny obowiązek ludzkości.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl22", word: "Henrietta Lacks", partOfSpeech: "postać historyczna", definition: "Afroamerykanka, której komórki rakowe (linia HeLa) stały się nieśmiertelne i zrewolucjonizowały medycynę — bez jej wiedzy i zgody.", example: "Komórki Henrietty Lacks pomogły opracować szczepionkę na polio i badać AIDS.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl23", word: "Comte de Saint-Germain", partOfSpeech: "postać historyczna", definition: "Tajemniczy europejski arystokrata XVIII w., który twierdził, że ma 300 lat. Alchemik, poliglota, muzyk i dyplomata.", example: "Saint-Germain podobno znał Kleopatrę osobiście — przynajmniej tak twierdził na salonach.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl24", word: "Rosalind Franklin", partOfSpeech: "postać historyczna", definition: "Brytyjska chemiczka, której zdjęcie rentgenowskie DNA (Foto 51) było kluczowe dla odkrycia podwójnej helisy.", example: "Franklin nie otrzymała Nobla — jej wkład doceniono dopiero po śmierci.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl25", word: "Diogenes Laertios", partOfSpeech: "postać historyczna", definition: "Grecki biograf filozofów z III w. Jego dzieło to jedyne zachowane źródło wiedzy o wielu starożytnych myślicielach.", example: "Bez Diogenesa Laertiosa nie wiedzielibyśmy prawie nic o Heraklicie czy Demokrycie.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl26", word: "Wojciech Bogusławski", partOfSpeech: "postać historyczna", definition: "Ojciec polskiego teatru narodowego. Aktor, reżyser i dyrektor, który stworzył polską scenę dramatyczną.", example: "Bogusławski wystawił 'Krakowiaków i Górali' — pierwszą polską operę narodową.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl27", word: "Nettie Stevens", partOfSpeech: "postać historyczna", definition: "Amerykańska genetyczka, która odkryła chromosomy X i Y determinujące płeć. Jej odkrycie przypisywano mężczyźnie.", example: "Stevens udowodniła, że płeć jest determinowana genetycznie, a nie środowiskowo.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl28", word: "Ibn Battuta", partOfSpeech: "postać historyczna", definition: "Marokański podróżnik z XIV w., który przebył 120 000 km — trzy razy więcej niż Marco Polo.", example: "Ibn Battuta odwiedził ponad 40 współczesnych krajów w ciągu 29 lat podróży.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl29", word: "Blaise Pascal", partOfSpeech: "postać historyczna", definition: "Francuski matematyk, fizyk i filozof. W wieku 16 lat napisał przełomową pracę o geometrii. Wynalazł kalkulator.", example: "Zakład Pascala to argument, że rozsądniej jest wierzyć w Boga niż nie wierzyć.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl30", word: "Lise Meitner", partOfSpeech: "postać historyczna", definition: "Austriacka fizyczka, która wyjaśniła rozszczepienie jądra atomowego. Pominięta przy Nagrodzie Nobla na rzecz Otto Hahna.", example: "Meitner odmówiła pracy nad bombą atomową z powodów etycznych.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl31", word: "Giordano Bruno", partOfSpeech: "postać historyczna", definition: "Włoski filozof spalony na stosie w 1600 r. za głoszenie, że Wszechświat jest nieskończony i istnieje wiele światów.", example: "Bruno wyprzedził swoją epokę o wieki — jego idee potwierdziła współczesna kosmologia.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl32", word: "Sophie Germain", partOfSpeech: "postać historyczna", definition: "Francuska matematyczka, która korespondowała z Gaussem pod męskim pseudonimem. Pionierka teorii sprężystości.", example: "Germain dokonała przełomu w wielkim twierdzeniu Fermata.", category: "ciekawi_ludzie", difficulty: "advanced" },
  { id: "cl33", word: "Stanisław Lem", partOfSpeech: "postać historyczna", definition: "Polski pisarz SF, filozof i futurolog. Przewidział internet, sztuczną inteligencję i rzeczywistość wirtualną.", example: "Lem jest najczęściej tłumaczonym polskim pisarzem — jego książki wydano w 40 językach.", category: "ciekawi_ludzie", difficulty: "beginner" },
  { id: "cl34", word: "Hatszepsut", partOfSpeech: "postać historyczna", definition: "Kobieta-faraon, która rządziła Egiptem przez 22 lata. Kazała przedstawiać się z brodą faraona.", example: "Hatszepsut budowała świątynie i wysyłała ekspedycje handlowe do Puntu.", category: "ciekawi_ludzie", difficulty: "intermediate" },
  { id: "cl35", word: "Évariste Galois", partOfSpeech: "postać historyczna", definition: "Francuski matematyk, który w noc przed śmiertelnym pojedynkiem zapisał fundamenty teorii grup — mając 20 lat.", example: "Galois napisał: 'Nie mam czasu' na marginesie swoich notatek — i zginął następnego dnia.", category: "ciekawi_ludzie", difficulty: "advanced" },

  // ===== BIZNES I FINANSE =====
  { id: "bf1", word: "Arbitraż", partOfSpeech: "rzeczownik", definition: "Wykorzystanie różnic cenowych na różnych rynkach do osiągnięcia zysku bez ryzyka. Arbitrażysta kupuje tanio na jednym rynku i sprzedaje drożej na drugim, zanim ceny się wyrównają. Współcześnie arbitraż realizują algorytmy komputerowe w milisekundach.", example: "1. Traderzy wykorzystują arbitraż na rynku walutowym — kupują dolary w Tokio, sprzedają w Londynie.\n2. Arbitraż kryptowalutowy polega na kupowaniu Bitcoina na giełdzie, gdzie jest tańszy, i natychmiastowej sprzedaży na droższej.", etymology: "z fr. arbitrage", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf2", word: "Amortyzacja", partOfSpeech: "rzeczownik", definition: "Stopniowe rozliczanie kosztu środka trwałego w czasie, odzwierciedlające jego zużycie. Amortyzacja pozwala rozłożyć duży wydatek inwestycyjny na wiele lat podatkowych. Jest obowiązkowa w rachunkowości i ma istotne konsekwencje podatkowe.", example: "1. Amortyzacja maszyn zmniejsza roczny podatek dochodowy firmy — koszt rozkłada się na 5 lat.\n2. Samochód firmowy amortyzuje się przez 5 lat — co roku odpisuje się 20% jego wartości.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf3", word: "Dywersyfikacja", partOfSpeech: "rzeczownik", definition: "Rozproszenie inwestycji lub działalności w celu zmniejszenia ryzyka — 'nie wkładaj wszystkich jajek do jednego koszyka'. Dywersyfikacja jest fundamentalną zasadą zarządzania portfelem inwestycyjnym. Może dotyczyć geografii, branż, klas aktywów lub walut.", example: "1. Dywersyfikacja portfela chroni przed stratami — jeśli akcje spadają, obligacje mogą rosnąć.\n2. Firma zdywersyfikowała działalność z produkcji mebli na projektowanie wnętrz i sprzedaż online.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf4", word: "Likwidność", partOfSpeech: "rzeczownik", definition: "Zdolność do szybkiej zamiany aktywów na gotówkę bez istotnej utraty wartości. Gotówka jest najbardziej płynnym aktywem, nieruchomości — jednym z najmniej. Brak likwidności może być śmiertelny dla firmy — nawet zyskownej.", example: "1. Nieruchomości mają niską likwidność w porównaniu z akcjami — ich sprzedaż trwa tygodnie.\n2. Kryzys likwidności w 2008 roku oznaczał, że banki nie pożyczały sobie nawet na noc.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf5", word: "Obligacja", partOfSpeech: "rzeczownik", definition: "Papier wartościowy potwierdzający dług emitenta wobec nabywcy, z obietnicą zwrotu kapitału i odsetek. Obligacje skarbowe uważa się za jedne z bezpieczniejszych inwestycji — stoi za nimi gwarancja państwa. Rynek obligacji jest większy niż rynek akcji.", example: "1. Obligacje skarbowe uważane są za jedną z bezpieczniejszych inwestycji — wypłaca je państwo.\n2. Firma wyemitowała obligacje korporacyjne, by sfinansować budowę nowej fabryki.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf6", word: "Konsolidacja", partOfSpeech: "rzeczownik", definition: "Łączenie firm, długów lub sprawozdań finansowych w jedną całość w celu osiągnięcia korzyści skali. Konsolidacja kredytów pozwala zamienić wiele rat na jedną, zwykle niższą. W biznesie oznacza fuzję firm lub integrację procesów.", example: "1. Konsolidacja kredytów pozwala zmniejszyć miesięczną ratę — zamiast pięciu rat płacisz jedną.\n2. Konsolidacja branży fitness — duże sieci wykupują małe siłownie i studia jogi.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf7", word: "Deflacja", partOfSpeech: "rzeczownik", definition: "Ogólny spadek poziomu cen w gospodarce — przeciwieństwo inflacji. Deflacja może wydawać się korzystna (niższe ceny), ale w rzeczywistości jest groźna — hamuje konsumpcję (po co kupować dziś, skoro jutro będzie taniej?). Japonia zmagała się z deflacją przez dwie dekady.", example: "1. Deflacja może być groźniejsza od inflacji — hamuje konsumpcję i inwestycje.\n2. W latach 90. Japonia wpadła w spiralę deflacyjną, z której nie mogła się wydostać przez 20 lat.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf8", word: "Stagflacja", partOfSpeech: "rzeczownik", definition: "Jednoczesne występowanie stagnacji gospodarczej (brak wzrostu, bezrobocie) i wysokiej inflacji — najgorsze z obu światów. Stagflacja lat 70. podważyła klasyczne teorie ekonomiczne, które zakładały, że te dwa zjawiska nie mogą współistnieć. Walka ze stagflacją jest niezwykle trudna — leczenie inflacji pogłębia recesję i odwrotnie.", example: "1. Stagflacja lat 70. XX wieku podważyła keynesowskie teorie ekonomiczne.\n2. Wzrost cen energii przy spowolnieniu gospodarczym budzi obawy przed powrotem stagflacji.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf9", word: "Lewarowanie", partOfSpeech: "rzeczownik", definition: "Wykorzystanie pożyczonych środków do zwiększenia potencjalnego zysku (i ryzyka) z inwestycji — inwestowanie 'na kredyt'. Lewarowanie działa jak dźwignia: zwielokrotnia zarówno zyski, jak i straty. Nadmierne lewarowanie było jedną z przyczyn kryzysu finansowego 2008 roku.", example: "1. Lewarowanie 1:10 oznacza, że za 1000 zł kontrolujesz pozycję wartą 10 000 zł.\n2. Nadmierne lewarowanie banków inwestycyjnych doprowadziło do krachu Lehman Brothers w 2008 roku.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf12", word: "Dywidenda", partOfSpeech: "rzeczownik", definition: "Część zysku spółki wypłacana akcjonariuszom — nagroda za posiadanie akcji. Dywidenda może być wypłacana gotówką lub w formie dodatkowych akcji. Spółki dywidendowe cieszą się popularnością wśród inwestorów szukających stabilnego dochodu.", example: "1. Spółka ogłosiła rekordową dywidendę po udanym roku — 5 zł na akcję.\n2. Warren Buffett woli spółki, które reinwestują zyski zamiast wypłacać dywidendę — tak rośnie ich wartość.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf13", word: "Rentowność", partOfSpeech: "rzeczownik", definition: "Stosunek zysku do zaangażowanych środków; miara efektywności inwestycji wyrażona w procentach. Rentowność pozwala porównać opłacalność różnych inwestycji niezależnie od ich skali. Wysoka rentowność przy niskim ryzyku to marzenie każdego inwestora — zwykle nierealne.", example: "1. Rentowność obligacji spadła do historycznie niskiego poziomu — 1,5% rocznie.\n2. Rentowność sprzedaży netto firmy wyniosła 12%, co oznacza, że z każdej złotówki przychodu zostawała 12 groszy zysku.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf14", word: "Kapitalizacja", partOfSpeech: "rzeczownik", definition: "Łączna wartość rynkowa wszystkich akcji spółki — ile rynek wycenia całą firmę. Kapitalizacja rynkowa to cena jednej akcji pomnożona przez liczbę wszystkich akcji. W bankowości kapitalizacja oznacza doliczanie odsetek do kapitału.", example: "1. Kapitalizacja rynkowa Microsoftu przekroczyła 3 biliony dolarów — więcej niż PKB większości krajów.\n2. Przy kapitalizacji kwartalnej odsetki od lokaty doliczane są co 3 miesiące i same zaczynają 'pracować'.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf16", word: "Demutualizacja", partOfSpeech: "rzeczownik", definition: "Przekształcenie organizacji wzajemnościowej (np. spółdzielni, giełdy) w spółkę akcyjną. Demutualizacja pozwala pozyskać kapitał od zewnętrznych inwestorów, ale zmienia charakter organizacji. Wiele giełd papierów wartościowych przeszło demutualizację na przełomie wieków.", example: "1. Demutualizacja giełdy pozwoliła jej pozyskać kapitał od inwestorów i zmodernizować systemy.\n2. Po demutualizacji ubezpieczyciel zmienił się ze spółdzielni członków w korporację notowaną na giełdzie.", category: "biznes_finanse", difficulty: "advanced" },
  { id: "bf17", word: "Embargo", partOfSpeech: "rzeczownik", definition: "Zakaz handlu z określonym krajem lub na określone towary — forma sankcji ekonomicznych lub politycznych. Embargo ma wywierać presję na rządy bez użycia siły militarnej. Skuteczność embarg jest dyskusyjna — często najbardziej cierpią zwykli obywatele.", example: "1. Embargo na ropę naftową z 1973 roku wywołało kryzys energetyczny w krajach zachodnich.\n2. Embargo handlowe na Kubę trwa od ponad 60 lat i jest jednym z najdłuższych w historii.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf18", word: "Oligopol", partOfSpeech: "rzeczownik", definition: "Struktura rynku zdominowana przez kilku dużych producentów, którzy kontrolują większość podaży. W oligopolu firmy wzajemnie obserwują swoje ceny i strategie. Oligopol różni się od monopolu — jest kilku graczy, nie jeden, ale wejście na rynek jest bardzo trudne.", example: "1. Rynek telekomunikacyjny w Polsce jest oligopolem — dominują trzy-cztery firmy.\n2. Rynek napojów gazowanych to klasyczny oligopol — Coca-Cola i PepsiCo kontrolują ponad 70% rynku.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf19", word: "Protekcjonizm", partOfSpeech: "rzeczownik", definition: "Polityka ochrony krajowego rynku przed zagraniczną konkurencją za pomocą ceł, kwot importowych i subsydiów. Protekcjonizm chroni lokalne firmy i miejsca pracy, ale podnosi ceny dla konsumentów. Debata między protekcjonizmem a wolnym handlem trwa od stuleci.", example: "1. Protekcjonizm celny może chronić lokalne firmy, ale podnosi ceny importowanych towarów.\n2. Administracja Trumpa zastosowała protekcjonizm wobec chińskich produktów, wprowadzając wysokie cła.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf20", word: "Syndykacja", partOfSpeech: "rzeczownik", definition: "Wspólne udzielenie dużego kredytu przez kilka banków w celu rozłożenia ryzyka. Syndykacja stosowana jest przy finansowaniu wielkich projektów infrastrukturalnych. Jeden bank pełni rolę lidera i organizatora konsorcjum.", example: "1. Syndykacja kredytu pozwoliła sfinansować budowę autostrady za 3 miliardy złotych.\n2. Żaden bank nie chciał sam ponieść ryzyka, dlatego zdecydowano się na syndykację z udziałem pięciu instytucji.", category: "biznes_finanse", difficulty: "advanced" },
  { id: "bf21", word: "Marża", partOfSpeech: "rzeczownik", definition: "Różnica między ceną sprzedaży a kosztem — zysk wyrażony w procentach lub kwotowo. Marża jest podstawowym wskaźnikiem rentowności handlu i produkcji. Wysoka marża oznacza duży zysk na pojedynczym produkcie, niska — konieczność dużego wolumenu sprzedaży.", example: "1. Marża na produktach luksusowych sięga 80% — perfumy za 400 zł kosztują w produkcji 80 zł.\n2. Supermarkety operują na niskich marżach (2–3%), ale nadrabiają ogromnym wolumenem sprzedaży.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf22", word: "Akwizycja", partOfSpeech: "rzeczownik", definition: "Przejęcie innej firmy lub pozyskiwanie nowych klientów. W kontekście korporacyjnym akwizycja oznacza zakup kontrolnego pakietu akcji innej spółki. Akwizycje mogą być przyjazne (za zgodą zarządu) lub wrogie (wbrew woli zarządu przejmowanej firmy).", example: "1. Akwizycja start-upu kosztowała korporację miliardy — ale dała dostęp do innowacyjnej technologii.\n2. Wroga akwizycja spotkała się z oporem zarządu — uruchomiono 'trującą pigułkę' jako obronę.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf23", word: "Restrukturyzacja", partOfSpeech: "rzeczownik", definition: "Głęboka przebudowa organizacji w celu poprawy efektywności, często wymuszana przez kryzys. Restrukturyzacja może obejmować zwolnienia, zmianę modelu biznesowego, sprzedaż aktywów lub renegocjację długów. Jest bolesna, ale bywa jedyną alternatywą dla upadłości.", example: "1. Restrukturyzacja firmy obejmowała zwolnienia 30% załogi i zamknięcie nierentownych oddziałów.\n2. Restrukturyzacja długu Grecji w 2012 roku oznaczała, że wierzyciele stracili ponad połowę pożyczonych pieniędzy.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf26", word: "Dezintermediacja", partOfSpeech: "rzeczownik", definition: "Eliminacja pośredników z łańcucha dostaw lub transakcji finansowych — bezpośredni kontakt producenta z konsumentem. Internet drastycznie przyspieszył dezintermediację w wielu branżach. Biura podróży, agenci nieruchomości i brokerzy tracą pozycję na rzecz platform cyfrowych.", example: "1. Internet umożliwił dezintermediację w branży turystycznej — rezerwujemy hotele bez biura podróży.\n2. Dezintermediacja w muzyce oznacza, że artyści wydają albumy sami na Spotify, bez wytwórni.", category: "biznes_finanse", difficulty: "advanced" },
  { id: "bf28", word: "Insolvencja", partOfSpeech: "rzeczownik", definition: "Trwała niezdolność do regulowania zobowiązań finansowych — sytuacja, gdy długi przekraczają aktywa. Insolvencja może prowadzić do upadłości lub restrukturyzacji. Różni się od braku płynności — tam problem jest tymczasowy, tu strukturalny.", example: "1. Insolvencja firmy doprowadziła do złożenia wniosku o upadłość — długi trzykrotnie przekraczały aktywa.\n2. Techniczna insolvencja oznacza, że firma ma ujemny kapitał własny — jest winna więcej niż posiada.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf29", word: "Kanibalizacja", partOfSpeech: "rzeczownik", definition: "Sytuacja, gdy nowy produkt firmy odbiera klientów jej starszemu produktowi zamiast pozyskiwać nowych. Kanibalizacja jest świadomym ryzykiem przy wprowadzaniu innowacji. Steve Jobs mawiał: 'Jeśli sam siebie nie skanibalzujesz, zrobi to ktoś inny.'", example: "1. iPhone skanibalizował sprzedaż iPodów Apple'a — po co kupować odtwarzacz, skoro telefon robi to samo?\n2. Wprowadzenie tańszego modelu samochodu skanibalizowało sprzedaż droższej wersji.", category: "biznes_finanse", difficulty: "intermediate" },
  { id: "bf35", word: "Antycykliczny", partOfSpeech: "przymiotnik", definition: "Działający wbrew cyklowi koniunkturalnemu — rosnący w recesji lub spadający w czasie prosperity. Polityka antycykliczna polega na stymulowaniu gospodarki w kryzysie i hamowaniu w czasie boomu. Inwestycje antycykliczne stanowią zabezpieczenie portfela.", example: "1. Złoto jest aktywem antycyklicznym — drożeje w kryzysach, gdy akcje tanieją.\n2. Antycykliczna polityka fiskalna oznacza zwiększanie wydatków państwa w recesji, by pobudzić gospodarkę.", category: "biznes_finanse", difficulty: "advanced" },
  { id: "bf36", word: "Hipoteka", partOfSpeech: "rzeczownik", definition: "Zabezpieczenie wierzytelności na nieruchomości — jeśli nie spłacisz kredytu, bank przejmuje dom. Hipoteka jest wpisywana do księgi wieczystej i daje bankowi pierwszeństwo w przypadku egzekucji. Kredyty hipoteczne są tańsze niż gotówkowe, właśnie dzięki temu zabezpieczeniu.", example: "1. Wzięli kredyt hipoteczny na 30 lat — dom służy jako zabezpieczenie dla banku.\n2. Kryzys 2008 roku zaczął się od hipotecznych kredytów subprime — udzielanych ludziom, którzy nie byli w stanie ich spłacić.", category: "biznes_finanse", difficulty: "beginner" },
  { id: "bf37", word: "Benchmarking", partOfSpeech: "rzeczownik", definition: "Porównywanie wyników, procesów lub praktyk firmy z najlepszymi w branży, w celu zidentyfikowania obszarów do poprawy. Benchmarking nie jest kopiowaniem — to nauka od najlepszych i adaptacja do własnych warunków. Jest podstawowym narzędziem zarządzania jakością.", example: "1. Firma przeprowadziła benchmarking i odkryła, że jej koszty logistyki są dwa razy wyższe niż u konkurencji.\n2. Benchmarking procesów obsługi klienta pokazał, że czas odpowiedzi można skrócić o połowę.", category: "biznes_finanse", difficulty: "intermediate" },

  // ===== RELIGIA =====
  { id: "r1", word: "Eschatologia", partOfSpeech: "rzeczownik", definition: "Nauka o rzeczach ostatecznych: śmierci, sądzie, niebie i piekle — o tym, co czeka ludzkość na końcu historii. Eschatologia jest obecna w większości religii — od chrześcijańskiego Apokalipsy po islamski Dzień Sądu. Współcześnie eschatologia wpływa na politykę i kulturę popularną.", example: "1. Eschatologia chrześcijańska opisuje Sąd Ostateczny jako moment rozliczenia ludzkości.\n2. Eschatologia żydowska koncentruje się na przyjściu Mesjasza i odbudowie Świątyni.", etymology: "z gr. eschatos — ostatni", category: "religia", difficulty: "advanced" },
  { id: "r2", word: "Teofania", partOfSpeech: "rzeczownik", definition: "Objawienie się bóstwa człowiekowi w widzialnej, postrzegalnej zmysłami formie. Teofanie biblijne obejmują gorejący krzew Mojżesza, głos z nieba przy chrzcie Jezusa i burze na górze Synaj. W religiach politeistycznych bogowie objawiali się często pod ludzką postacią.", example: "1. Gorejący krzew Mojżesza jest jedną z najsłynniejszych teofanii w Biblii.\n2. W hinduizmie awatary Wisznu — od ryby po Krysznę — to różne formy teofanii.", category: "religia", difficulty: "advanced" },
  { id: "r3", word: "Apofatyczny", partOfSpeech: "przymiotnik", definition: "Określający Boga przez negację — mówiący, czym Bóg nie jest, zamiast czym jest. Teologia apofatyczna uznaje, że język ludzki jest zbyt ograniczony, by opisać nieskończoność Boga. Jest to droga mistyczna popularna w prawosławiu i u Pseudo-Dionizego.", example: "1. Teologia apofatyczna stwierdza: Bóg nie jest zły, nie jest ograniczony, nie jest materialny — ale nie mówi, czym jest.\n2. Apofatyczne podejście Mistrza Eckharta prowadziło do mówienia o 'Bożym mroku' — ciemności przekraczającej światło.", category: "religia", difficulty: "advanced" },
  { id: "r4", word: "Synkretyzm", partOfSpeech: "rzeczownik", definition: "Łączenie elementów różnych religii, filozofii lub kultur w nową, hybrydową całość. Synkretyzm jest naturalnym procesem historycznym — religie ewoluują, absorbując elementy spotkanych kultur. Krytycy widzą w synkretyzmie rozmycie oryginalnego przesłania.", example: "1. Voodoo jest przykładem synkretyzmu afrykańskich wierzeń i katolicyzmu — orishe zrównano ze świętymi.\n2. Bożonarodzeniowa choinka to relikt synkretyzmu — chrześcijaństwo wchłonęło pogański kult drzew.", category: "religia", difficulty: "intermediate" },
  { id: "r5", word: "Hagiografia", partOfSpeech: "rzeczownik", definition: "Piśmiennictwo poświęcone żywotom świętych, często idealizujące i pełne cudownych opowieści. Przenośnie — bezkrytyczny, upiększony opis jakiejś osoby lub zjawiska. Hagiografia średniowieczna była głównym gatunkiem literackim przez wieki.", example: "1. Hagiografia średniowieczna pełna była cudów i legend — święci latali, leczyli i rozmawiali ze zwierzętami.\n2. Biografia prezydenta to czysta hagiografia — ani słowa o porażkach czy kontrowersyjnych decyzjach.", category: "religia", difficulty: "intermediate" },
  { id: "r6", word: "Soteriologia", partOfSpeech: "rzeczownik", definition: "Nauka teologiczna o zbawieniu — jak, przez co i dla kogo jest ono dostępne. Soteriologia stoi w centrum sporów teologicznych: czy zbawienie jest z łaski, z uczynków, czy z wiary? Różne religie mają radykalnie odmienne soteriologie.", example: "1. Soteriologia Pawła z Tarsu kładła nacisk na łaskę, nie uczynki — zbawienie jest darem.\n2. Buddyjska soteriologia opiera się na ośmiorakiej ścieżce prowadzącej do wyzwolenia z cierpienia.", category: "religia", difficulty: "advanced" },
  { id: "r7", word: "Herezja", partOfSpeech: "rzeczownik", definition: "Pogląd religijny sprzeczny z oficjalną doktryną kościoła; wybór doktryny uznanej za błędną. W starożytności i średniowieczu za herezję groziły surowe kary, włącznie ze stosem. Przenośnie — pogląd radykalnie odmienny od ogólnie przyjętego.", example: "1. Arianizm uznano za herezję na soborze nicejskim w 325 roku — zaprzeczał boskości Chrystusa.\n2. W korporacji kwestionowanie strategii szefa traktowane jest niemal jak herezja.", category: "religia", difficulty: "beginner" },
  { id: "r8", word: "Pneumatologia", partOfSpeech: "rzeczownik", definition: "Dział teologii dotyczący Ducha Świętego — Jego natury, działania i roli w Trójcy Świętej. Pneumatologia wschodnia i zachodnia różnią się w kwestii Filioque — czy Duch pochodzi od Ojca, czy od Ojca i Syna. Jest to jeden z najgłębszych sporów w historii chrześcijaństwa.", example: "1. Pneumatologia wschodnia różni się od zachodniej kwestią Filioque — spór trwający tysiąc lat.\n2. Ruch zielonoświątkowy ożywił zainteresowanie pneumatologią — darami i działaniem Ducha Świętego.", category: "religia", difficulty: "advanced" },
  { id: "r9", word: "Predestynacja", partOfSpeech: "rzeczownik", definition: "Doktryna o z góry ustalonym przez Boga przeznaczeniu duszy do zbawienia lub potępienia. Kalwin głosił 'podwójną predestynację' — Bóg z góry wybrał, kto będzie zbawiony, a kto potępiony. Doktryna ta rodzi fundamentalne pytania o wolną wolę i sprawiedliwość Boga.", example: "1. Kalwin głosił podwójną predestynację — do zbawienia i potępienia, niezależnie od uczynków.\n2. Doktryna predestynacji paradoksalnie motywowała protestantów do pracy — sukces materialny miał być 'znakiem wybrania'.", category: "religia", difficulty: "intermediate" },
  { id: "r10", word: "Kenoza", partOfSpeech: "rzeczownik", definition: "Uniżenie się Boga; w teologii — Chrystus dobrowolnie rezygnujący z boskich atrybutów, by stać się człowiekiem. Kenoza jest jedną z najgłębszych tajemnic chrześcijaństwa — nieskończony Bóg staje się skończony. Pojęcie to pochodzi z Listu do Filipian.", example: "1. Kenoza oznacza, że Bóg dobrowolnie przyjął ludzką słabość — cierpienie, głód, samotność.\n2. Teologia kenozy mówi, że Bóg nie jest odległy — sam doświadczył ludzkiego bólu.", etymology: "z gr. kenosis — ogołocenie", category: "religia", difficulty: "advanced" },
  { id: "r11", word: "Ikonoklazm", partOfSpeech: "rzeczownik", definition: "Ruch niszczenia obrazów i ikon religijnych, uważanych za formę bałwochwalstwa. Ikonoklazm bizantyjski trwał ponad sto lat (726–843) i podzielił cesarstwo. Przenośnie — zwalczanie autorytetów, tradycji i świętości.", example: "1. Ikonoklazm bizantyjski trwał ponad sto lat — niszczono bezcenne mozaiki i freski.\n2. Każde pokolenie artystów uprawia pewien ikonoklazm — burzy autorytety, by zbudować własne.", category: "religia", difficulty: "intermediate" },
  { id: "r12", word: "Epifania", partOfSpeech: "rzeczownik", definition: "Objawienie, nagłe olśnienie — moment, w którym prawda staje się nagle jasna. W religii — ukazanie się bóstwa lub prawdy nadprzyrodzonej. James Joyce użył tego terminu w literaturze — 'epifanie' to momenty nagłego wglądu w istotę rzeczy.", example: "1. Epifania to także święto Trzech Króli w tradycji chrześcijańskiej — ukazanie się Chrystusa poganom.\n2. Miał epifanię podczas spaceru — nagle zrozumiał, że musi zmienić zawód.", category: "religia", difficulty: "intermediate" },
  { id: "r13", word: "Antynomia", partOfSpeech: "rzeczownik", definition: "Sprzeczność między dwoma prawami, zasadami lub twierdzeniami, które wydają się równie uzasadnione. W teologii antynomie są częste — np. wolna wola versus Boże wszechwiedza. Kant pokazał, że rozum ludzki nieuchronnie wpada w antynomie, próbując poznać to, co przekracza doświadczenie.", example: "1. Antynomia między wolną wolą a predestynacją nurtuje teologów od wieków — obie strony mają mocne argumenty.\n2. Kant opisał cztery antynomie czystego rozumu — np. czy świat ma początek w czasie, czy nie.", category: "religia", difficulty: "advanced" },
  { id: "r14", word: "Panenteizm", partOfSpeech: "rzeczownik", definition: "Pogląd, że Bóg przenika cały świat, ale jednocześnie go przekracza — jest w świecie, ale jest czymś więcej niż świat. Panenteizm różni się od panteizmu (Bóg = świat) i teizmu klasycznego (Bóg poza światem). Jest atrakcyjny dla tych, którzy szukają Boga w przyrodzie, nie rezygnując z Jego transcendencji.", example: "1. Panenteizm łączy transcendencję z immanencją Boga — Bóg jest w drzewie, ale jest też ponad drzewem.\n2. Wielu ekoteologów skłania się ku panenteizmowi — pozwala on traktować przyrodę jako sakralną.", category: "religia", difficulty: "advanced" },
  { id: "r19", word: "Doktryna", partOfSpeech: "rzeczownik", definition: "Usystematyzowany zbiór prawd wiary, zasad lub poglądów tworzących spójny system. Doktryny religijne kształtowały się przez wieki debat, soborów i sporów teologicznych. Przenośnie — każdy zbiór zasad stanowiących fundament działania.", example: "1. Doktryna Trójcy Świętej kształtowała się przez pierwsze wieki chrześcijaństwa — nie była oczywista od początku.\n2. Doktryna Monroe'a głosiła, że obie Ameryki nie powinny być terenem kolonizacji europejskiej.", category: "religia", difficulty: "beginner" },
  { id: "r20", word: "Asceza", partOfSpeech: "rzeczownik", definition: "Praktyka duchowa polegająca na wyrzeczeniach, umartwieniach i samodyscyplinie w celu duchowego doskonalenia. Asceza jest obecna w niemal wszystkich tradycjach religijnych — od chrześcijańskiego monastycyzmu po hinduistyczną tapas. Nadmierna asceza bywa jednak krytykowana jako destrukcyjna.", example: "1. Asceza monastyczna obejmowała posty, milczenie i pracę fizyczną — mnisi wstawali o 3 w nocy.\n2. Budda odrzucił skrajną ascezę na rzecz 'drogi środka' — umiarkowania między luksusem a umartwieniem.", category: "religia", difficulty: "intermediate" },
  { id: "r21", word: "Ekumenizm", partOfSpeech: "rzeczownik", definition: "Ruch dążący do jedności i współpracy między różnymi wyznaniami chrześcijańskimi. Ekumenizm nie oznacza rezygnacji z własnej tożsamości, lecz szukanie tego, co wspólne. Sobór Watykański II dał impuls ekumenizmowi w Kościele katolickim.", example: "1. Sobór Watykański II dał impuls ekumenizmowi — katolicy po raz pierwszy modlili się z protestantami.\n2. Ekumeniczne nabożeństwo zgromadziło pastora, księdza i duchownego prawosławnego przy jednym ołtarzu.", category: "religia", difficulty: "intermediate" },
  { id: "r23", word: "Liturgia", partOfSpeech: "rzeczownik", definition: "Publiczny kult religijny; ustalone formy nabożeństwa obejmujące modlitwy, śpiewy i rytuały. Liturgia nie jest improwizacją — jej struktura kształtowała się przez wieki i ma głęboką symbolikę. Liturgia bizantyjska zachwyca bogactwem, łacińska — surowością i precyzją.", example: "1. Liturgia bizantyjska zachwyca bogactwem symboliki, ikon, kadzidła i wielogłosowego śpiewu.\n2. Reforma liturgiczna po Soborze Watykańskim II zastąpiła łacinę językami narodowymi.", category: "religia", difficulty: "beginner" },
  { id: "r24", word: "Katecheza", partOfSpeech: "rzeczownik", definition: "Nauczanie podstaw wiary; systematyczna instrukcja religijna przygotowująca do sakramentów. W pierwotnym Kościele katecheza trwała nawet trzy lata — katechumeni uczyli się wiary przed chrztem. Współcześnie katecheza odbywa się w szkołach i parafiach.", example: "1. Katecheza przygotowywała katechumenów do przyjęcia chrztu — trwała nawet trzy lata.\n2. Współczesna katecheza w szkole różni się od dawnej — kładzie nacisk na dialog, nie na pamięciowe uczenie się.", category: "religia", difficulty: "beginner" },
  { id: "r26", word: "Deizm", partOfSpeech: "rzeczownik", definition: "Wiara w Boga-Stwórcę, który stworzył świat, nadał mu prawa, ale potem nie ingeruje w jego bieg. Deiści porównują Boga do zegarmistrza — zbudował mechanizm i go nakręcił, ale nie poprawia go na bieżąco. Deizm był popularny wśród myślicieli Oświecenia.", example: "1. Wielu ojców założycieli USA, jak Jefferson i Franklin, wyznawało deizm — Bóg stworzył, ale nie interweniuje.\n2. Deizm odrzuca cuda — jeśli Bóg stworzył doskonałe prawa natury, nie musi ich łamać.", category: "religia", difficulty: "intermediate" },
  { id: "r27", word: "Mistycyzm", partOfSpeech: "rzeczownik", definition: "Dążenie do bezpośredniego, osobistego doświadczenia Boga lub absolutu, wykraczającego poza intelekt i dogmaty. Mistycyzm jest obecny we wszystkich tradycjach religijnych — od sufizmu po kabałę i Zen. Mistycy opisują swoje doświadczenia jako niewyrażalne słowami.", example: "1. Mistycyzm suficki wyraża się w poetyckiej miłości do Boga — Rumi pisał: 'Tam, gdzie kończą się słowa, zaczyna się muzyka.'\n2. Karmelitańska tradycja mistyczna — Jan od Krzyża i Teresa z Ávili — opisuje 'ciemną noc duszy'.", category: "religia", difficulty: "intermediate" },
  { id: "r32", word: "Schizma", partOfSpeech: "rzeczownik", definition: "Rozłam w obrębie wspólnoty religijnej — podział na odrębne, często wrogie sobie frakcje. Wielka Schizma Wschodnia z 1054 roku podzieliła chrześcijaństwo na katolicyzm i prawosławie. Schizmy bywają wynikiem sporów doktrynalnych, ale też politycznych i personalnych.", example: "1. Wielka Schizma Wschodnia z 1054 roku podzieliła chrześcijaństwo na Kościół zachodni i wschodni.\n2. Schizma zachodnia (1378–1417) doprowadziła do sytuacji, w której rządziło jednocześnie trzech papieży.", category: "religia", difficulty: "intermediate" },
  { id: "r34", word: "Monoteizm", partOfSpeech: "rzeczownik", definition: "Wiara w jednego Boga — fundament trzech wielkich religii abrahamowych: judaizmu, chrześcijaństwa i islamu. Monoteizm nie był oczywisty — starożytny Izrael przechodził długą drogę od henoteizmu do czystego monoteizmu. Debata o granicach monoteizmu (np. Trójca Święta) trwa do dziś.", example: "1. Judaizm, chrześcijaństwo i islam to religie monoteistyczne — wyznają wiarę w jednego Boga.\n2. Echnaton, faraon Egiptu, próbował wprowadzić monoteizm (kult Atona) na 1300 lat przed Chrystusem.", category: "religia", difficulty: "beginner" },
  { id: "r35", word: "Panteizm", partOfSpeech: "rzeczownik", definition: "Utożsamianie Boga z przyrodą i całym wszechświatem — wszystko, co istnieje, jest Bogiem i Bóg jest wszystkim. Spinoza był najbardziej znanym filozofem-panteistą — głosił 'Deus sive Natura' (Bóg czyli Natura). Panteizm różni się od panenteizmu tym, że nie zakłada żadnej transcendencji.", example: "1. Spinoza głosił panteizm — Bóg i natura są jednym i tym samym.\n2. Panteizm wzbudza kontrowersje: czy skoro wszystko jest Bogiem, to czy Bóg w ogóle jest czymś szczególnym?", category: "religia", difficulty: "intermediate" },
  { id: "r36", word: "Teodycea", partOfSpeech: "rzeczownik", definition: "Próba pogodzenia istnienia wszechmocnego i dobrego Boga z istnieniem zła i cierpienia na świecie. 'Jeśli Bóg jest dobry i wszechmocny, dlaczego cierpią niewinni?' — to pytanie teodyceii. Leibniz ukuł termin, twierdząc, że żyjemy w 'najlepszym z możliwych światów'.", example: "1. Teodycea Leibniza głosiła, że żyjemy w najlepszym z możliwych światów — mimo cierpienia.\n2. Holocaust postawił teodyceę przed najtrudniejszym pytaniem: gdzie był Bóg w Auschwitz?", etymology: "z gr. theos + dikē — Bóg + sprawiedliwość", category: "religia", difficulty: "intermediate" },
  { id: "r37", word: "Prozelityzm", partOfSpeech: "rzeczownik", definition: "Gorliwe nawracanie ludzi na swoją wiarę, często nachalnie i agresywnie. Prozelityzm bywa postrzegany negatywnie jako forma duchowej presji. Papież Franciszek odróżnia ewangelizację (świadectwo życia) od prozelityzmu (presja konwersji).", example: "1. Prozelityzm sekt polega na bombardowaniu psychicznym i izolowaniu nowych członków od rodziny.\n2. Papież Franciszek powiedział: 'Prozelityzm to nonsens. Trzeba poznawać, słuchać i rozmawiać.'", category: "religia", difficulty: "intermediate" },

  // ===== HISTORIA =====
  { id: "h1", word: "Anachronizm", partOfSpeech: "rzeczownik", definition: "Element niezgodny z epoką, w której jest umieszczony — np. zegarek na ręce gladiatora. Anachronizm może być błędem (w filmach historycznych) lub celowym zabiegiem artystycznym. Przenośnie — przeżytek, relikt przeszłości.", example: "1. Zegarek na ręce gladiatora w filmie to rażący anachronizm — w starożytnym Rzymie nie było zegarków.\n2. Monarchia absolutna w XXI wieku to polityczny anachronizm.", category: "historia", difficulty: "beginner" },
  { id: "h2", word: "Autokracja", partOfSpeech: "rzeczownik", definition: "Forma rządów, w której pełnia władzy spoczywa w rękach jednej osoby, bez ograniczeń prawnych czy instytucjonalnych. Autokracja różni się od dyktatury — autokrata może rządzić na podstawie tradycji (car), dyktator — siły. Współczesne autokracje często maskują się fasadą demokratyczną.", example: "1. Rosja carska była przykładem absolutnej autokracji — car był źródłem wszelkiego prawa.\n2. Współczesne autokracje organizują wybory, ale kontrolują media, sądy i opozycję.", category: "historia", difficulty: "beginner" },
  { id: "h3", word: "Historiografia", partOfSpeech: "rzeczownik", definition: "Nauka o pisaniu historii, metodach badań historycznych i sposobach interpretacji przeszłości. Historiografia nie pyta tylko 'co się wydarzyło?', ale 'kto o tym pisał i dlaczego tak?'. Każda epoka pisze historię na nowo — historiografia jest więc 'historią historii'.", example: "1. Historiografia marksistowska interpretowała dzieje przez pryzmat walki klas i stosunków produkcji.\n2. Współczesna historiografia bada nie tylko wielkie bitwy, ale życie codzienne zwykłych ludzi.", category: "historia", difficulty: "intermediate" },
  { id: "h4", word: "Feudalizm", partOfSpeech: "rzeczownik", definition: "System społeczno-polityczny oparty na zależności lennej — senior nadawał wasalowi ziemię w zamian za służbę wojskową i wierność. Feudalizm dominował w Europie od IX do XIV wieku. System ten tworzył piramidę władzy od króla przez możnych po chłopów pańszczyźnianych.", example: "1. Feudalizm europejski opierał się na wymianie ziemi za wierność — wasal przysięgał seniorowi.\n2. W systemie feudalnym chłop nie mógł opuścić ziemi pana — był przywiązany do niej jak do łańcucha.", category: "historia", difficulty: "beginner" },
  { id: "h5", word: "Suzerenitet", partOfSpeech: "rzeczownik", definition: "Zwierzchnictwo jednego państwa nad drugim przy zachowaniu formalnej autonomii tego drugiego. Państwo zwierzchnie (suzeren) kontroluje politykę zagraniczną wasala i pobiera daniny. Suzerenitet był typową formą relacji w imperium osmańskim i chińskim.", example: "1. Cesarstwo Osmańskie sprawowało suzerenitet nad Księstwami Naddunajskimi — miały autonomię, ale płaciły trybut.\n2. Tybetański suzerenitet Chin jest do dziś przedmiotem sporów — Chiny twierdzą, że Tybet był zawsze ich częścią.", category: "historia", difficulty: "advanced" },
  { id: "h6", word: "Irredentyzm", partOfSpeech: "rzeczownik", definition: "Ruch polityczny dążący do przyłączenia terytoriów zamieszkałych przez rodaków poza granicami własnego państwa. Termin pochodzi od włoskiego Italia irredenta — 'niewyzwolone Włochy' — i odnosił się do ziem włoskojęzycznych pod panowaniem Austrii. Irredentyzm był jednym z zapalników wojen i konfliktów XX wieku.", example: "1. Włoski irredentyzm dążył do włączenia Triestu i Trydenu — ziem zamieszkałych przez Włochów pod rządami Austrii.\n2. Irredentyzm niemiecki w latach 30. dotyczył Sudetów — Hitler 'wyzwalał' Niemców za granicą.", category: "historia", difficulty: "advanced" },
  { id: "h7", word: "Ostracyzm", partOfSpeech: "rzeczownik", definition: "W starożytnych Atenach — głosowanie o wygnaniu obywatela na 10 lat, zapisywane na glinianych skorupkach. Ostracyzm miał chronić demokrację przed tyranami i demagogami. Przenośnie — wykluczenie z grupy społecznej, towarzyski bojkot.", example: "1. Temistokles padł ofiarą ostracyzmu mimo swoich zasług — Ateńczycy bali się jego rosnącej władzy.\n2. Po wyrażeniu kontrowersyjnych opinii spotkał go ostracyzm środowiskowy — nikt nie chciał z nim rozmawiać.", etymology: "z gr. ostrakon — skorupka", category: "historia", difficulty: "intermediate" },
  { id: "h8", word: "Autarkia", partOfSpeech: "rzeczownik", definition: "Samowystarczalność gospodarcza państwa — niezależność od importu i handlu zagranicznego. Autarkia jest ideałem wielu reżimów autorytarnych, ale w praktyce prawie nieosiągalna. Próby autarkii zwykle prowadzą do niedoborów i obniżenia poziomu życia.", example: "1. Korea Północna bezskutecznie dąży do autarkii — izolacja prowadzi do klęsk głodowych.\n2. Polityka autarkii III Rzeszy obejmowała produkcję syntetycznej benzyny i gumy — kosztowną i nieefektywną.", category: "historia", difficulty: "intermediate" },
  { id: "h9", word: "Hegemonia", partOfSpeech: "rzeczownik", definition: "Dominacja jednego państwa, grupy społecznej lub idei nad innymi — często na tyle subtelna, że wydaje się naturalna. Gramsci rozwinął pojęcie hegemonii kulturowej — klasa rządząca narzuca swoje wartości jako 'zdrowy rozsądek'. Hegemonia nie opiera się wyłącznie na sile, ale na zgodzie rządzonych.", example: "1. Hegemonia Sparty po wojnie peloponeskiej była krótkotrwała — Teby ją przełamały.\n2. Hegemonia kulturowa USA sprawia, że amerykańskie filmy, muzyka i jedzenie dominują na całym świecie.", category: "historia", difficulty: "beginner" },
  { id: "h10", word: "Thalassokracja", partOfSpeech: "rzeczownik", definition: "Panowanie na morzu; państwo opierające swoją potęgę na flocie morskiej i kontroli szlaków handlowych. Thalassokracje historyczne to m.in. Ateny, Wenecja, Holandia i Wielka Brytania. Kontrola mórz oznaczała kontrolę handlu, a więc bogactwa i wpływów.", example: "1. Wielka Brytania była największą thalassokracją w historii — 'Britannia rządzi falami' to nie pusty slogan.\n2. Wenecja zbudowała thalassokrację na Morzu Śródziemnym — kontrolowała handel między Europą a Azją.", category: "historia", difficulty: "advanced" },
  { id: "h11", word: "Abdykacja", partOfSpeech: "rzeczownik", definition: "Dobrowolne zrzeczenie się władzy, zwłaszcza przez monarchę — akt rezygnacji z tronu. Abdykacja może być wymuszona (rewolucja) lub dobrowolna (zmęczenie władzą). Jest to jeden z najdramatyczniejszych aktów politycznych.", example: "1. Abdykacja cara Mikołaja II w 1917 roku zakończyła trzy wieki dynastii Romanowów.\n2. Edward VIII abdykował z tronu Wielkiej Brytanii, by poślubić rozwódkę — wybierając miłość nad koroną.", category: "historia", difficulty: "beginner" },
  { id: "h13", word: "Damnatio memoriae", partOfSpeech: "rzeczownik", definition: "Starożytna rzymska praktyka wymazywania pamięci o skazanym z historii — niszczenie portretów, posągów i inskrypcji z jego imieniem. Damnatio memoriae było karą gorszą niż śmierć — unicestwienie samego istnienia osoby. Podobne praktyki stosowane są do dziś — Stalin retuszował zdjęcia.", example: "1. Po zabójstwie Domicjana senat uchwalił damnatio memoriae — usunięto jego imię ze wszystkich inskrypcji.\n2. Stalin stosował współczesną damnatio memoriae — wymazywał wrogów ze zdjęć, jakby nigdy nie istnieli.", etymology: "łac. — potępienie pamięci", category: "historia", difficulty: "advanced" },
  { id: "h14", word: "Pax Romana", partOfSpeech: "rzeczownik", definition: "Okres względnego pokoju w Imperium Rzymskim trwający ponad 200 lat (27 p.n.e. — 180 n.e.). Pax Romana nie oznaczał braku wojen — Rzym nadal podbijał — ale stabilność wewnętrzną i rozkwit handlu. Był jednym z najdłuższych okresów pokoju w historii Europy.", example: "1. Pax Romana sprzyjał rozwojowi handlu i kultury — z Londynu do Jerozolimy podróżowano po rzymskich drogach.\n2. Pod Pax Romana powstawały wielkie budowle — Koloseum, Panteon, akwedukty — symbol potęgi cywilizacyjnej.", category: "historia", difficulty: "intermediate" },
  { id: "h15", word: "Realpolitik", partOfSpeech: "rzeczownik", definition: "Polityka oparta na pragmatyzmie, interesie i realistycznej ocenie sił — nie na ideologii, moralności czy ideałach. Bismarck był mistrzem Realpolitik — 'wielkie pytania epoki rozstrzyga się żelazem i krwią, nie przemówieniami'. Realpolitik bywa krytykowana za cynizm, ale też ceniona za skuteczność.", example: "1. Bismarck był mistrzem Realpolitik — sojusze zawierał i zrywał w zależności od sytuacji.\n2. Kissinger uprawiał Realpolitik, nawiązując stosunki z komunistycznymi Chinami — idealista by tego nie zrobił.", etymology: "z niem.", category: "historia", difficulty: "intermediate" },
  { id: "h16", word: "Casus belli", partOfSpeech: "rzeczownik", definition: "Wydarzenie, okoliczność lub pretekst uzasadniający wypowiedzenie wojny. Casus belli może być realny lub sfabrykowany — wiele wojen zaczęło się od prowokacji. W prawie międzynarodowym casus belli musi spełniać warunki 'wojny sprawiedliwej'.", example: "1. Zamach w Sarajewie stał się casus belli I wojny światowej — choć prawdziwe przyczyny były głębsze.\n2. Incydent w Zatoce Tonkińskiej był sfabrykowanym casus belli — USA wykorzystały go do eskalacji wojny w Wietnamie.", etymology: "łac. — powód wojny", category: "historia", difficulty: "intermediate" },
  { id: "h17", word: "Diaspora", partOfSpeech: "rzeczownik", definition: "Rozproszenie narodu poza granicami ojczyzny; społeczność żyjąca na obczyźnie, zachowująca tożsamość kulturową. Pierwotnie termin odnosił się do Żydów żyjących poza Palestyną. Współcześnie mówi się o diasporze polskiej, ukraińskiej, armenskiej i wielu innych.", example: "1. Diaspora żydowska istniała na długo przed zburzeniem Świątyni — wspólnoty żyły od Babilonu po Aleksandrię.\n2. Polska diaspora w Chicago jest tak duża, że miasto bywa żartobliwie nazywane 'największym polskim miastem poza Polską'.", category: "historia", difficulty: "beginner" },
  { id: "h18", word: "Egalitaryzm", partOfSpeech: "rzeczownik", definition: "Dążenie do równości społecznej i politycznej wszystkich ludzi, niezależnie od pochodzenia, płci czy majątku. Egalitaryzm był jednym z haseł rewolucji francuskiej — 'Wolność, Równość, Braterstwo'. W praktyce egalitaryzm napotyka na opór — nierówności mają tendencję do odtwarzania się.", example: "1. Egalitaryzm był jednym z haseł rewolucji francuskiej — choć rychło zastąpił go terror.\n2. Skandynawski model społeczny jest najbliższy ideałowi egalitaryzmu — niskie nierówności i silna klasa średnia.", category: "historia", difficulty: "intermediate" },
  { id: "h20", word: "Kolaboracja", partOfSpeech: "rzeczownik", definition: "Współpraca z okupantem, zdrada na rzecz wroga — jedno z najcięższych oskarżeń w czasach wojny. Motywacje kolaborantów bywały różne — od ideologii przez strach po chęć zysku. Po wojnie kolaboracja karana była surowymi wyrokami, a czasem samosądem.", example: "1. Kolaboracja z nazistami była po wojnie surowo karana — we Francji publicznie golono głowy kobiet współpracujących z Niemcami.\n2. Granica między kolaboracją a przetrwaniem bywa cienka — czy sprzedawanie chleba okupantowi to zdrada?", category: "historia", difficulty: "beginner" },
  { id: "h24", word: "Pogrom", partOfSpeech: "rzeczownik", definition: "Zorganizowany, masowy atak na mniejszość etniczną lub religijną, często z milczącą zgodą lub aktywnym udziałem władz. Pogromy żydowskie w carskiej Rosji zmusiły miliony ludzi do emigracji. Termin pochodzi z rosyjskiego 'pogrom' — zniszczenie.", example: "1. Pogromy w carskiej Rosji zmusiły tysiące Żydów do emigracji — wielu trafiło do Ameryki.\n2. Noc Kryształowa (1938) była pogromem na niespotykaną skalę — spalono synagogi i zdemolowano tysiące sklepów.", category: "historia", difficulty: "beginner" },
  { id: "h25", word: "Szlachta", partOfSpeech: "rzeczownik", definition: "Stan uprzywilejowany w dawnej Polsce; warstwa rycersko-ziemiańska posiadająca prawa polityczne i przywileje. Szlachta polska stanowiła ok. 10% społeczeństwa — wyjątek w Europie, gdzie odsetek szlachty wynosił zwykle 1–2%. Szlachta ukształtowała polską kulturę polityczną i mentalność.", example: "1. Szlachta polska stanowiła ok. 10% społeczeństwa — wyjątek w Europie, gdzie zwykle było 1–2%.\n2. Tradycja szlachecka wpłynęła na polską kulturę — gościnność, honor, ale też kłótliwość i anarchia.", category: "historia", difficulty: "beginner" },
  { id: "h26", word: "Interregnum", partOfSpeech: "rzeczownik", definition: "Okres bezkrólewia; czas między panowaniem dwóch władców, często pełen niepewności i rywalizacji o władzę. W Rzeczypospolitej interregnum było regulowane prawem — prymas pełnił funkcję interreksa. Interregnum to czas, gdy stare reguły nie obowiązują, a nowe jeszcze nie powstały.", example: "1. Interregnum po śmierci Zygmunta Augusta trwało dwa lata — rywalizowało kilku kandydatów do tronu.\n2. Gramsci pisał o 'interregnum' między starym a nowym porządkiem — 'stary świat umiera, a nowy nie może się narodzić'.", category: "historia", difficulty: "intermediate" },
  { id: "h35", word: "Liberum veto", partOfSpeech: "rzeczownik", definition: "Prawo każdego posła do zerwania obrad sejmowych jednym głosem sprzeciwu — unikalny w skali świata przywilej polskiej szlachty. Liberum veto miało chronić wolność jednostki, ale w praktyce paraliżowało państwo. Obce dwory przekupywały posłów, by zrywali sejmy.", example: "1. Liberum veto paraliżowało politykę Rzeczypospolitej od XVII wieku — między 1652 a 1764 zerwano 73 z 150 sejmów.\n2. Liberum veto było wyrazem szlacheckiego idealizmu — 'wolność nad życie' — ale w praktyce niszczyło państwo.", category: "historia", difficulty: "beginner" },
  { id: "h36", word: "Rewizjonizm", partOfSpeech: "rzeczownik", definition: "Dążenie do rewizji (zmiany) ustalonych granic, traktatów lub interpretacji historycznych. W polityce rewizjonizm oznacza kwestionowanie status quo — np. granic ustalonych po wojnie. W historiografii to reinterpretacja zdarzeń historycznych z nowej perspektywy.", example: "1. Rewizjonizm niemiecki po I wojnie dążył do zmiany granic traktatu wersalskiego.\n2. Rewizjonizm historyczny może być wartościowy — nowe źródła zmieniają obraz przeszłości — lub niebezpieczny, gdy służy propagandzie.", category: "historia", difficulty: "intermediate" },
  { id: "h37", word: "Meritokracja", partOfSpeech: "rzeczownik", definition: "System, w którym awans i władza zależą od zasług, kompetencji i talentu, a nie od urodzenia czy koneksji. Meritokracja brzmi jak ideał, ale krytycy wskazują, że 'zasługi' nie są niezależne od warunków startu — bogaci mają lepsze szkoły. Termin ukuł Michael Young — ironicznie, jako ostrzeżenie.", example: "1. Singapur uchodzi za model meritokracji — awansuje się na podstawie wyników, nie znajomości.\n2. Krytycy meritokracji twierdzą, że jest mitem — dzieci lekarzy zostają lekarzami nie dlatego, że są najzdolniejsze.", category: "historia", difficulty: "intermediate" },

  // ===== SZTUKA =====
  { id: "s1", word: "Chiaroscuro", partOfSpeech: "rzeczownik", definition: "Technika malarska polegająca na silnym kontraście światła i cienia, tworzącym dramatyczny efekt głębi i objętości. Caravaggio doprowadził chiaroscuro do perfekcji — jego postacie wyłaniają się z ciemności jak z innego świata. Technika ta wpłynęła na fotografię i kino noir.", example: "1. Caravaggio był mistrzem chiaroscuro — jego postacie wyłaniają się z absolutnej ciemności.\n2. Filmowe chiaroscuro w 'Obywatelu Kane' Wellesa buduje atmosferę tajemnicy i władzy.", etymology: "z wł. chiaro (jasny) + scuro (ciemny)", category: "sztuka", difficulty: "intermediate" },
  { id: "s2", word: "Sfumato", partOfSpeech: "rzeczownik", definition: "Technika malarska polegająca na miękkim, dymnym rozmywaniu konturów i przejść tonalnych — bez ostrych linii. Leonardo da Vinci był niekwestionowanym mistrzem sfumato — nakładał dziesiątki warstw przezroczystej farby. Tajemniczy uśmiech Mony Lisy to efekt sfumato.", example: "1. Uśmiech Mony Lisy zawdzięcza tajemniczość technice sfumato — kontur ust dosłownie znika.\n2. Leonardo nakładał sfumato warstwa po warstwie — Mona Lisa powstawała przez kilkanaście lat.", etymology: "z wł. sfumare — znikać jak dym", category: "sztuka", difficulty: "intermediate" },
  { id: "s3", word: "Trompe-l'œil", partOfSpeech: "rzeczownik", definition: "Złudzenie optyczne w malarstwie — obraz tak realistyczny, że wydaje się trójwymiarowy i oszukuje oko widza. Starożytni Grecy opowiadali o malarzu Zeuksisie, którego namalowane winogrona próbowały dziobać ptaki. Trompe-l'œil to triumf techniki nad percepcją.", example: "1. Freski na suficie katedry to mistrzowski trompe-l'œil — kopuła wydaje się sięgać nieba.\n2. Graffiti 3D na chodnikach to współczesna forma trompe-l'œil — przechodnie 'wpadają' w namalowane przepaście.", etymology: "z fr. — oszukać oko", category: "sztuka", difficulty: "advanced" },
  { id: "s4", word: "Impasto", partOfSpeech: "rzeczownik", definition: "Technika nakładania grubych, widocznych warstw farby, tworzących faktury i relief na powierzchni płótna. Van Gogh stosował impasto tak grube, że farba wystaje z powierzchni obrazu na centymetry. Impasto nadaje obrazom dynamikę, energię i zmysłowość.", example: "1. Van Gogh stosował impasto, by nadać obrazom dynamikę — 'Gwiaździsta noc' to wiry grubej farby.\n2. Dotknięcie obrazu namalowanego impasto pozwala 'poczuć' ruch pędzla artysty.", category: "sztuka", difficulty: "intermediate" },
  { id: "s5", word: "Pentimento", partOfSpeech: "rzeczownik", definition: "Ślad wcześniejszej kompozycji przebijający przez warstwę farby — artysta zmienił zdanie, ale czas odsłania ukryte warstwy. Pentimento jest oknem do twórczego procesu — pokazuje wahania i decyzje malarza. Współczesna technologia (RTG, podczerwień) ujawnia pentimenta niewidoczne gołym okiem.", example: "1. Rentgen ujawnił pentimento — pod portretem kryła się inna twarz, przemalowana przez artystę.\n2. Pentimenta na obrazach Velázqueza pokazują, że wielokrotnie zmieniał pozycję postaci.", etymology: "z wł. pentirsi — żałować", category: "sztuka", difficulty: "advanced" },
  { id: "s6", word: "Patyna", partOfSpeech: "rzeczownik", definition: "Nalot tworzący się na powierzchni metalu, kamienia lub drewna z upływem czasu — ślad starzenia nadający szlachetność. Patyna brązu ma charakterystyczny zielonkawy kolor (verdigris). Przenośnie — piętno czasu, które nobilituje.", example: "1. Patyna na brązowym posągu nadaje mu szlachetny, zielonkawy odcień — to korozja miedzi.\n2. Stare meble z patyną są cenniejsze niż nowe — ślady czasu dodają im autentyczności.", category: "sztuka", difficulty: "beginner" },
  { id: "s7", word: "Kontrapunkt", partOfSpeech: "rzeczownik", definition: "Technika muzyczna łączenia dwóch lub więcej niezależnych melodii w harmonijną całość. Bach doprowadził sztukę kontrapunktu do absolutnej perfekcji — jego fugi to arcydzieła logiki muzycznej. Przenośnie — zestawienie kontrastujących elementów.", example: "1. Fugi Bacha to arcydzieła kontrapunktu — każdy głos jest niezależny, a razem tworzą doskonałą harmonię.\n2. W filmie Godarda sceny przemocy stanowią kontrapunkt do spokojnych dialogów o filozofii.", category: "sztuka", difficulty: "intermediate" },
  { id: "s8", word: "Synestezja", partOfSpeech: "rzeczownik", definition: "Zjawisko łączenia wrażeń zmysłowych — np. widzenie dźwięków jako kolorów lub smakowanie kształtów. Synestezja dotyka ok. 4% populacji i jest szczególnie częsta wśród artystów. Kandinsky malował muzykę, Nabokov widział litery w kolorach.", example: "1. Kandinsky malował muzykę dzięki swojej synestezji — dźwięki widział jako kolory i kształty.\n2. Nabokov miał synestezję literowo-kolorową — litera 'a' była dla niego czarna, 'e' żółta.", category: "sztuka", difficulty: "intermediate" },
  { id: "s9", word: "Pastisz", partOfSpeech: "rzeczownik", definition: "Utwór naśladujący styl innego artysty lub epoki — z podziwem, nie z intencją parodii czy kpiny. Pastisz jest hołdem złożonym mistrzowi — 'tak bym chciał tworzyć'. W postmodernizmie granica między pastiszem a oryginalnością jest celowo zacierana.", example: "1. Film 'La La Land' jest pastiszem klasycznych musicali lat 50. — hołdem dla złotej ery Hollywood.\n2. Pastisz różni się od parodii: parodia śmieje się z oryginału, pastisz go celebruje.", category: "sztuka", difficulty: "intermediate" },
  { id: "s10", word: "Groteskowy", partOfSpeech: "przymiotnik", definition: "Absurdalnie zniekształcony, łączący komizm z przerażeniem, piękno z brzydotą. Groteska jest jedną z najstarszych form artystycznych — od masek teatralnych po twórczość Boscha i Kafki. Groteskowe dzieła budzą śmiech i niepokój jednocześnie.", example: "1. Groteskowe postacie Boscha — hybrydy ludzi, zwierząt i maszyn — do dziś fascynują i przerażają.\n2. Kafka jest mistrzem literackiej groteska — Gregor Samsa budzi się jako karaluch, a rodzina martwi się, że spóźni się do pracy.", category: "sztuka", difficulty: "beginner" },
  { id: "s11", word: "Koloryt", partOfSpeech: "rzeczownik", definition: "Ogólny charakter barw w dziele malarskim; gama kolorystyczna nadająca obrazowi nastrój i atmosferę. Ciepły koloryt (złota, brązy, czerwienie) tworzy intymność, chłodny (błękity, szarości) — dystans i melancholię. Koloryt jest jednym z najważniejszych narzędzi ekspresji malarza.", example: "1. Ciepły koloryt obrazów Rembrandta tworzy intymną, niemal kameralną atmosferę.\n2. Chłodny koloryt zimowych pejzaży Brueghla oddaje mroźną ciszę flamandzkiej zimy.", category: "sztuka", difficulty: "beginner" },
  { id: "s13", word: "Fresk", partOfSpeech: "rzeczownik", definition: "Malowidło ścienne wykonane na mokrym tynku — pigmenty wnikają w ścianę i stają się jej częścią, co zapewnia trwałość na wieki. Technika freskowa wymaga szybkości i pewności — na mokrym tynku nie można poprawek. Freski Michała Anioła w Kaplicy Sykstyńskiej to ikona renesansu.", example: "1. Freski Michała Anioła w Kaplicy Sykstyńskiej powstawały przez cztery lata — artysta malował leżąc na rusztowaniu.\n2. Fresk różni się od muralu tym, że farba jest nakładana na mokry tynk, nie na suchy.", category: "sztuka", difficulty: "beginner" },
  { id: "s14", word: "Akwarela", partOfSpeech: "rzeczownik", definition: "Technika malowania farbami wodnymi na wilgotnym papierze — przezroczyste warstwy farby przepuszczają światło papieru. Akwarela wymaga odwagi — jest nieodwracalna, nie można zakryć błędu. Turner był mistrzem akwareli — jego pejzaże oddają ulotność światła i mgły.", example: "1. Akwarele Turnera oddają ulotność światła nad morzem — mgła, chmury i fale zlewają się w jedno.\n2. Akwarela jest techniką wymagającą odwagi — jeden nieprzemyślany pociągnięcie pędzla może zniszczyć całą pracę.", category: "sztuka", difficulty: "beginner" },
  { id: "s17", word: "Kubizm", partOfSpeech: "rzeczownik", definition: "Kierunek w sztuce rozbijający formy na geometryczne bryły i ukazujący obiekt z wielu perspektyw jednocześnie. Kubizm, zapoczątkowany przez Picassa i Braque'a ok. 1907 roku, był jedną z najradykalniejszych rewolucji w historii sztuki. Zamiast 'jak to wygląda?', kubizm pyta 'czym to jest?'.", example: "1. Kubizm Picassa i Braque'a zmienił sposób patrzenia na rzeczywistość — pokazał obiekt ze wszystkich stron naraz.\n2. 'Panny z Avinionu' Picassa to manifest kubizmu — twarze rozpadają się na ostre kąty i płaszczyzny.", category: "sztuka", difficulty: "beginner" },
  { id: "s18", word: "Secesja", partOfSpeech: "rzeczownik", definition: "Styl artystyczny przełomu XIX i XX wieku cechujący się ornamentalnością, płynnymi liniami i motywami roślinnymi. Secesja (Art Nouveau, Jugendstil) przenikała wszystko — od architektury po biżuterię i plakaty. Była reakcją na industrializację — próbą przywrócenia piękna codziennemu życiu.", example: "1. Kamienice secesyjne Wiednia i Krakowa zachwycają dekoracjami fasad — kwiaty, kobiety, fale.\n2. Secesyjne stacje metra w Paryżu, zaprojektowane przez Guimarda, to ikony Art Nouveau.", category: "sztuka", difficulty: "intermediate" },
  { id: "s19", word: "Dadaizm", partOfSpeech: "rzeczownik", definition: "Awangardowy ruch artystyczny negujący tradycyjne wartości estetyczne, logikę i sens — jako protest przeciw absurdowi I wojny światowej. Dadaiści tworzyli 'antysztukę' — losowe kolaże, absurdalną poezję i prowokacyjne performance. Dadaizm był krótkotrwały, ale wywarł ogromny wpływ na surrealizm i sztukę konceptualną.", example: "1. Dadaiści organizowali absurdalne wieczory poetyckie w Zurychu — recytowali losowe słowa przy akompaniamencie gwizdków.\n2. Marcel Duchamp, związany z dadaizmem, wystawił pisuar jako rzeźbę — 'Fontanna' zrewolucjonizowała pojęcie sztuki.", category: "sztuka", difficulty: "intermediate" },
  { id: "s22", word: "Plener", partOfSpeech: "rzeczownik", definition: "Malowanie na świeżym powietrzu, w bezpośrednim kontakcie z naturą i naturalnym światłem. Plener stał się możliwy dzięki wynalezieniu farb w tubkach w XIX wieku — wcześniej malarze musieli sami mieszać pigmenty. Impresjoniści uczynili z pleneru rewolucję — wynieśli sztukę z pracowni.", example: "1. Impresjoniści wyszli na plener, by uchwycić naturalne światło — malowali szybko, zanim się zmieniło.\n2. Monet malował tę samą katedrę w Rouen wielokrotnie en plein air — za każdym razem światło było inne.", category: "sztuka", difficulty: "beginner" },
  { id: "s24", word: "Anamorfoza", partOfSpeech: "rzeczownik", definition: "Zniekształcony obraz, który ujawnia właściwą formę dopiero pod określonym kątem lub za pomocą lustra cylindrycznego. Anamorfoza jest zabawą z percepcją — to, co widzimy, zależy od punktu widzenia. Najsłynniejsza anamorfoza to czaszka w 'Ambasadorach' Holbeina.", example: "1. Anamorfoza czaszki w 'Ambasadorach' Holbeina widoczna jest tylko pod bardzo ostrym kątem — z boku.\n2. Współczesne murale anamorficzne na ulicach tworzą iluzję głębi — chodnik 'otwiera się' w przepaść.", category: "sztuka", difficulty: "advanced" },
  { id: "s25", word: "Minimalizm", partOfSpeech: "rzeczownik", definition: "Nurt artystyczny redukujący formę do absolutnie podstawowych elementów — prostych kształtów, czystych kolorów, minimum detali. Minimalizm głosi: 'mniej znaczy więcej' — siła tkwi w prostocie i oszczędności środków. Wpłynął na sztukę, architekturę, design, muzykę i styl życia.", example: "1. Minimalizm Donalda Judda wykorzystuje proste geometryczne bryły — aluminiowe pudła, nic więcej.\n2. Minimalizm w muzyce — Steve Reich, Philip Glass — opiera się na powtarzaniu prostych motywów z subtelnymi zmianami.", category: "sztuka", difficulty: "beginner" },
  { id: "s26", word: "Instalacja", partOfSpeech: "rzeczownik", definition: "Trójwymiarowe dzieło artystyczne zaaranżowane w określonej przestrzeni — widz wchodzi do dzieła, a nie tylko je ogląda. Instalacje mogą angażować wszystkie zmysły — wzrok, słuch, dotyk, zapach. Są efemeryczne — istnieją tylko przez czas wystawy, potem znikają.", example: "1. Instalacje Olafura Eliassona zmieniają percepcję przestrzeni — sztuczne słońce w Tate Modern odwiedziły 2 miliony ludzi.\n2. Yayoi Kusama tworzy instalacje 'Infinity Rooms' — pokoje pełne luster i świateł, w których czujesz się jak w kosmosie.", category: "sztuka", difficulty: "beginner" },
  { id: "s28", word: "Wabi-sabi", partOfSpeech: "rzeczownik", definition: "Japońska estetyka piękna tkwiącego w niedoskonałości, przemijaniu, prostocie i naturalnym starzeniu się. Wabi-sabi jest antytezą zachodniej obsesji na punkcie perfekcji i nowości. Pęknięta ceramika naprawiona złotem (kintsugi) jest kwintesencją tej filozofii — skaza staje się ozdobą.", example: "1. Pęknięta ceramika naprawiona złotem (kintsugi) to kwintesencja wabi-sabi — piękno w niedoskonałości.\n2. Wabi-sabi uczy, że pęknięcie w ścianie, mech na kamieniu i zardzewiały gwoźdź mają własne piękno.", category: "sztuka", difficulty: "intermediate" },
  { id: "s29", word: "Bauhaus", partOfSpeech: "rzeczownik", definition: "Niemiecka szkoła projektowania (1919–1933) łącząca sztukę z rzemiosłem i przemysłem — forma ma wynikać z funkcji. Bauhaus zrewolucjonizował architekturę, typografię, meble i wzornictwo przemysłowe. Zamknięty przez nazistów, ale jego idee kształtują design do dziś.", example: "1. Bauhaus zrewolucjonizował architekturę, wzornictwo i typografię — prostota, funkcjonalność, brak ornamentu.\n2. Krzesło Marcela Breuera z rurek stalowych to ikona Bauhausu — piękno tkwi w konstrukcji.", category: "sztuka", difficulty: "beginner" },
  { id: "s30", word: "Kicz", partOfSpeech: "rzeczownik", definition: "Dzieło pretensjonalne, tandetne, naśladujące sztukę wyższą bez zrozumienia jej istoty. Kicz jest przeciwieństwem autentyczności — udaje emocje, których nie odczuwa. Milan Kundera pisał, że kicz to 'absolutne zaprzeczenie gówna' — negacja wszystkiego, co brzydkie, trudne i prawdziwe.", example: "1. Kicz jest przeciwieństwem autentyczności w sztuce — plastikowe aniołki zamiast rzeźby.\n2. Kundera definiował kicz polityczny jako świat, w którym 'nie ma miejsca na indywidualizm i wątpliwości'.", category: "sztuka", difficulty: "beginner" },
  { id: "s31", word: "Dyptyk", partOfSpeech: "rzeczownik", definition: "Dzieło złożone z dwóch połączonych tablic, paneli lub części, tworzących spójną całość. Dyptyki ołtarzowe w średniowieczu można było składać — chroniło to obrazy podczas transportu. Współcześnie dyptyk oznacza każde dzieło w dwóch częściach — film, książkę, fotografię.", example: "1. Średniowieczne dyptyki ołtarzowe przedstawiały sceny biblijne na dwóch skrzydłach — można je było składać.\n2. Fotograficzny dyptyk zestawiał portret matki z 1950 roku z portretem córki z 2020 — identyczny kadr, inne epoki.", category: "sztuka", difficulty: "intermediate" },
  { id: "s33", word: "Frotaż", partOfSpeech: "rzeczownik", definition: "Technika artystyczna polegająca na odciskaniu faktury powierzchni przez pocieranie ołówkiem lub kredką po papierze nałożonym na teksturowany obiekt. Max Ernst wykorzystał frotaż jako technikę surrealistyczną — przypadkowe wzory pobudzały wyobraźnię. Technika ta jest prosta, ale wyniki bywają zaskakujące.", example: "1. Max Ernst popularyzował frotaż jako technikę surrealistyczną — przypadkowe faktury stawały się krajobrazami snów.\n2. Dzieci instynktownie odkrywają frotaż — kładą kartkę na monecie i pocierają ołówkiem.", category: "sztuka", difficulty: "intermediate" },
  { id: "s34", word: "Enkaustyka", partOfSpeech: "rzeczownik", definition: "Starożytna technika malarska z użyciem pigmentów zmieszanych z gorącym woskiem pszczelim. Enkaustyka daje niezwykle żywe, głębokie kolory i jest niezwykle trwała — portrety fajumskie z I–III w. n.e. wyglądają jak namalowane wczoraj. Technika ta odradza się we współczesnej sztuce.", example: "1. Portrety fajumskie malowano techniką enkaustyki — przetrwały blisko 2000 lat w doskonałym stanie.\n2. Współcześni artyści redukują enkaustykę — nakładają warstwy kolorowego wosku rozgrzanego palnikiem.", category: "sztuka", difficulty: "advanced" },
  { id: "s35", word: "Monochromia", partOfSpeech: "rzeczownik", definition: "Użycie jednego koloru w różnych odcieniach, tonach i nasyceniach — z wykluczeniem innych barw. Monochromia zmusza artystę do wyrażania głębi, emocji i formy za pomocą jednego koloru. Yves Klein stworzył własny odcień niebieskiego (IKB) i malował nim wszystko.", example: "1. Monochromia niebieska Yves'a Kleina stała się jego znakiem rozpoznawczym — 'International Klein Blue'.\n2. Picasso miał 'okres niebieski' — monochromia niebieska wyrażała smutek, samotność i biedę.", category: "sztuka", difficulty: "intermediate" },
  { id: "s36", word: "Ready-made", partOfSpeech: "rzeczownik", definition: "Przedmiot codziennego użytku wyniesiony do rangi dzieła sztuki przez sam gest artysty — bez żadnej przeróbki. Marcel Duchamp zapoczątkował ready-made w 1917 roku, wystawiając pisuar jako rzeźbę 'Fontanna'. Kluczowe pytanie: co czyni coś sztuką — sam obiekt czy kontekst?", example: "1. 'Fontanna' Duchampa — zwykły pisuar podpisany 'R. Mutt' — zrewolucjonizowała definicję sztuki.\n2. Ready-made pokazuje, że sztuką może być wszystko — liczy się intencja artysty i kontekst wystawy.", etymology: "z ang. — gotowy, z półki", category: "sztuka", difficulty: "intermediate" },
  { id: "s37", word: "Performance", partOfSpeech: "rzeczownik", definition: "Forma sztuki, w której ciało artysty staje się medium — dzieło jest żywym, efemerycznym wydarzeniem. Performance art nie produkuje obiektów — jest doświadczeniem, które istnieje tylko tu i teraz. Marina Abramović siedziała nieruchomo w MoMA przez 736 godzin, patrząc w oczy widzom.", example: "1. Marina Abramović w 'The Artist Is Present' siedziała nieruchomo przez trzy miesiące — widzowie płakali.\n2. Yoko Ono w 'Cut Piece' pozwoliła widzom odcinać kawałki jej ubrania — badając granice zaufania.", category: "sztuka", difficulty: "intermediate" },
  { id: "s38", word: "Vanitas", partOfSpeech: "rzeczownik", definition: "Gatunek malarstwa martwej natury przypominający o przemijaniu życia — czaszki, zwiędłe kwiaty, gasące świece, zepsute owoce. Vanitas rozkwitł w XVII-wiecznej Holandii — w epoce bogactwa artyści przypominali: 'memento mori'. Przesłanie: piękno, bogactwo i sława — wszystko mija.", example: "1. Na obrazach vanitas czaszka obok złotego zegarka przypomina: czas mija, bogactwo nie uratuje.\n2. Współczesny vanitas to zdjęcie iPhone'a z pękniętym ekranem obok więdnących róż — technologia też przemija.", etymology: "z łac. vanitas — próżność, marność", category: "sztuka", difficulty: "intermediate" },
];
